function teacherCard(t){
  return `<article class="card ${t.featured?'highlight':''}">
    <div class="kicker">${t.featured?'Featured teacher':'Teacher profile'}</div>
    <h3>${t.name}</h3><p><strong>${t.title}</strong></p><p class="muted">${t.timezone} · ${t.languages.join(', ')}</p>
    <div class="tag-row">${t.specialties.map(s=>`<span class="tag">${s}</span>`).join('')}</div>
    <div class="lesson-credit"><span>Public pricing</span><strong>Package matched</strong></div>
    <div class="lesson-credit"><span>Teacher category</span><strong>${t.publicCategory}</strong></div>
    <div class="lesson-credit"><span>Quality completion</span><strong>${t.completion || 'New'}${t.completion?'%':''}</strong></div>
    <div class="lesson-credit"><span>Shareable profile</span><strong>${t.status==='Approved'?'Tracking ready':'Pending approval'}</strong></div>
    <button class="btn block js-toast" data-toast="Teacher match request saved for ${t.name}.">Request this teacher</button>
  </article>`;
}


function teacherMarketingSection(){
  const totalLeads = teacherCampaigns.reduce((a,c)=>a+c.leads,0);
  const totalConverted = teacherCampaigns.reduce((a,c)=>a+c.converted,0);
  const totalRevenue = teacherCampaigns.reduce((a,c)=>a+c.revenue,0);
  const totalBonus = teacherCampaigns.reduce((a,c)=>a+c.bonus,0);
  return `<section class="section" id="teacher-growth">
    <div class="container section-head"><div><div class="eyebrow">Teacher marketing toolkit</div><h2>Let teachers help bring students and employer clients — without losing pricing control.</h2></div><p>Approved teachers can market their own expertise through EnglishLegalese profile links, class spotlights, social posts, webinars, QR codes, and employer intro assets. Every lead stays attributed and every sale still uses EnglishLegalese packages.</p></div>
    <div class="container grid cols-2">
      <article class="card highlight"><h3>Growth rules</h3><ul class="feature-list">${marketingRules.map(rule=>`<li>${rule}</li>`).join('')}</ul><p class="clean-note"><strong>Best model:</strong> teachers market their expertise; EnglishLegalese owns checkout, package pricing, lesson credits, reporting, quality review, and employer relationships.</p></article>
      <article class="card"><h3>Teacher-sourced revenue dashboard</h3><div class="stat-grid" style="grid-template-columns:1fr 1fr"><div class="stat"><strong>${totalLeads}</strong><span>Tracked leads</span></div><div class="stat"><strong>${totalConverted}</strong><span>Conversions</span></div><div class="stat"><strong>$${totalRevenue.toLocaleString()}</strong><span>Revenue influenced</span></div><div class="stat"><strong>$${totalBonus.toLocaleString()}</strong><span>Marketing bonuses</span></div></div><p class="notice"><strong>Suggested bonus policy:</strong> $25 for converted individual package leads, $50 for Professional 10, and 3%–5% of first employer package up to a staff-approved cap. Bonuses require attribution and completed payment.</p></article>
    </div>
    <div class="container grid cols-3" style="margin-top:18px">${marketingAssets.map(marketingAssetCard).join('')}</div>
    <div class="container panel" style="margin-top:18px"><div class="panel-head"><div><h3>Campaign tracking</h3><p class="muted">This helps staff see which teachers are bringing real business and which campaigns need approval.</p></div><button class="btn gold js-toast" data-toast="New teacher campaign draft created for admin approval.">Create campaign</button></div><div class="table-wrap"><table class="table"><tr><th>Teacher</th><th>Code</th><th>Channel</th><th>Focus</th><th>Leads</th><th>Converted</th><th>Revenue</th><th>Bonus</th><th>Status</th></tr>${teacherCampaigns.map(c=>`<tr><td>${c.teacher}</td><td><strong>${c.code}</strong></td><td>${c.channel}</td><td>${c.focus}</td><td>${c.leads}</td><td>${c.converted}</td><td>$${c.revenue.toLocaleString()}</td><td>$${c.bonus}</td><td><span class="status ${c.status==='Active'?'green':c.status==='Paused'?'gray':'gold'}">${c.status}</span></td></tr>`).join('')}</table></div></div>
  </section>`;
}
function marketingAssetCard(a){
  return `<article class="marketing-card"><div class="kicker">${a.format}</div><h3>${a.name}</h3><p>${a.purpose}</p><div class="lesson-credit"><span>Audience</span><strong>${a.audience}</strong></div><div class="tag-row"><button class="btn light small js-toast" data-toast="${a.name} preview opened.">Preview</button><button class="btn teal small js-toast" data-toast="Trackable ${a.name.toLowerCase()} copied with teacher attribution.">Copy link</button></div></article>`;
}

function classroomRoom(title, subtitle, agenda, people){
  return `<div class="video-room">
    <div class="kicker" style="color:#e8d39a">Live classroom</div>
    <h2 style="color:white;font-size:40px">${title}</h2>
    <p style="color:#DDE6F0;margin-top:-6px">${subtitle}</p>
    <ol class="agenda-list">${agenda.map(item=>`<li>${item}</li>`).join('')}</ol>
    <div class="avatar-grid">${people.map(p=>`<div class="avatar">${p}</div>`).join('')}</div>
    <div class="room-tools"><button class="tool-btn js-toast" data-toast="Video provider placeholder. Connect Zoom, Google Meet, or WebRTC later.">Start video</button><button class="tool-btn js-toast" data-toast="Attendance captured for this prototype session.">Take attendance</button><button class="tool-btn js-toast" data-toast="Lesson notes saved. Completion report updated.">Save notes</button><button class="tool-btn js-scroll-report">Generate report</button></div>
  </div>`;
}

function classroomsSection(){
  const individual = state.classroom === 'individual';
  const agenda = individual ? ['Review prior homework and corrections','Practice U.S. legal memo transitions','Roleplay professor/student class discussion','Assign writing revision homework'] : ['Group warm-up: concise client updates','Breakout roleplay: contract delay notice','Team vocabulary drill: risk and obligation language','Assign group homework and individual practice'];
  const people = individual ? ['Maya Chen, JD','Ana Kowalska'] : ['Teacher','Ana','Marco','Hana','Arjun','Observer'];
  return `<section class="section" id="classrooms">
    <div class="container section-head"><div><div class="eyebrow">Classrooms</div><h2>Individual and group learning rooms.</h2></div><p>Each classroom includes teacher notes, attendance, SmartTeacher AI, homework assignment tools, files, and completion reporting.</p></div>
    <div class="container micro-tabs"><button data-classroom="individual" class="js-classroom ${individual?'active':''}">Individual classroom</button><button data-classroom="group" class="js-classroom ${!individual?'active':''}">Group classroom</button></div>
    <div class="container classroom">
      ${classroomRoom(individual?'Individual Legal English Classroom':'Firm Group Classroom', individual?'Ana Kowalska · LL.M. legal writing track':'GlobalLex Partners · Contract communication cohort', agenda, people)}
      <div class="side-stack">
        ${classroomSidePanel(individual)}
        ${aiAssistantBox(true)}
      </div>
    </div>
  </section>`;
}
function classroomSidePanel(individual){
  return `<div class="panel" style="margin-bottom:0"><h3>${individual?'Student lesson panel':'Cohort lesson panel'}</h3>
    <div class="lesson-credit"><span>Credits used after completion</span><strong>${individual?'1':'4'}</strong></div>
    <div class="lesson-credit"><span>Homework due</span><strong>${individual?'1 assignment':'4 assignments'}</strong></div>
    <div class="lesson-credit"><span>Report status</span><strong>Draft ready</strong></div>
    <div class="lesson-credit"><span>Teacher note status</span><strong>Needed</strong></div>
    <div class="tag-row"><button class="btn teal js-scroll-homework">Create homework</button><button class="btn light js-toast" data-toast="Lesson notes saved to staff review queue.">Save lesson notes</button></div>
  </div>`;
}

function aiAssistantBox(compact=false){
  return `<div class="ai-box" id="ai-box"><div class="panel-head" style="margin-bottom:8px"><div><h3>SmartTeacher AI</h3><p class="muted" style="margin:0">Language practice only — not legal advice.</p></div></div>
    <div class="chat-window" id="chatWindow">${state.aiMessages.map(m=>`<div class="bubble ${m.from==='ai'?'ai':'user'}">${escapeHtml(m.text)}</div>`).join('')}</div>
    <div class="input-row"><input id="aiInput" placeholder="Ask for a vocabulary drill, email rewrite, or roleplay..." /><button class="btn teal" id="aiSend">Send</button></div>
    ${compact?'':`<div class="tag-row"><button class="btn light small js-ai-prompt" data-prompt="Create a Legal English homework drill about contract obligations.">Contract drill</button><button class="btn light small js-ai-prompt" data-prompt="Help me rewrite a client email in concise Legal English.">Email rewrite</button><button class="btn light small js-ai-prompt" data-prompt="Roleplay a law-firm client call about a delayed matter.">Client call</button></div>`}
  </div>`;
}

function homeworkSection(){
  return `<section class="section alt" id="homework">
    <div class="container section-head"><div><div class="eyebrow">Homework assignments</div><h2>Homework is a core product feature.</h2></div><p>Students complete assignments. Teachers create, review, and score them. Employers and admin see completion without exposing sensitive private student details unnecessarily.</p></div>
    <div class="container grid cols-2">
      <div class="panel" style="margin-bottom:0">
        <div class="panel-head"><div><h3>Create assignment</h3><p class="muted">Teacher-created homework connects live lessons to daily practice.</p></div></div>
        <form class="form-grid" id="assignmentForm">
          <div class="field"><label>Student / cohort</label><select id="hwStudent">${students.map(s=>`<option>${s.name}</option>`).join('')}<option>GlobalLex Cohort A</option></select></div>
          <div class="field"><label>Track</label><select id="hwTrack"><option>Legal writing</option><option>Contracts</option><option>TOLES Advanced</option><option>Client calls</option><option>Compliance</option><option>Negotiation</option></select></div>
          <div class="field span-2"><label>Assignment title</label><input id="hwTitle" required placeholder="Example: Rewrite a client status update"></div>
          <div class="field"><label>Due date</label><input id="hwDue" type="date"></div>
          <div class="field"><label>Teacher</label><select id="hwTeacher">${teachers.filter(t=>t.status==='Approved').map(t=>`<option>${t.name}</option>`).join('')}</select></div>
          <div class="field span-2"><label>Instructions</label><textarea id="hwInstructions" placeholder="Give clear instructions, word count, vocabulary goals, and what SmartTeacher AI may help with."></textarea></div>
          <button class="btn gold" type="submit">Assign homework</button><button class="btn light" type="button" id="seedHomework">Add sample assignment</button>
        </form>
      </div>
      <div class="panel" style="margin-bottom:0">
        <div class="panel-head"><div><h3>Assignment queue</h3><p class="muted">The same queue feeds student, teacher, employer, and admin dashboards.</p></div><button class="btn light small" id="resetHomework">Reset demo</button></div>
        <div id="assignmentList">${assignmentList()}</div>
      </div>
    </div>
  </section>`;
}
function assignmentList(limit){
  const list = limit ? state.assignments.slice(0, limit) : state.assignments;
  return list.map(a=>assignmentCard(a)).join('') || '<p class="muted">No assignments yet.</p>';
}
function assignmentCard(a){
  const done = a.status === 'Completed' || a.status === 'Submitted';
  const score = a.score ? `${a.score}%` : 'Pending';
  const statusClass = a.status === 'Submitted' || a.status === 'Completed' ? 'green' : a.status === 'Needs Revision' ? 'red' : 'gold';
  return `<div class="assignment-card ${done?'done':''}" data-id="${a.id}">
    <div class="assignment-top"><div><h3 style="font-size:18px;margin-bottom:6px">${escapeHtml(a.title)}</h3><div class="assignment-meta"><span>${escapeHtml(a.student)}</span><span>${escapeHtml(a.track)}</span><span>Due ${escapeHtml(a.due)}</span><span>${escapeHtml(a.teacher)}</span></div></div><span class="status ${statusClass}">${escapeHtml(a.status)}</span></div>
    <p class="muted" style="margin:0">${escapeHtml(a.instructions)}</p>
    <div class="rubric"><div><strong>${score}</strong><span>Score</span></div><div><strong>${a.status==='Assigned'?'Open':'Reviewed'}</strong><span>Review</span></div><div><strong>${a.employer || 'Individual'}</strong><span>Account</span></div><div><strong>${a.track}</strong><span>Skill</span></div></div>
    <div class="tag-row"><button class="btn light small js-complete" data-id="${a.id}">Mark complete</button><button class="btn light small js-toast" data-toast="Teacher feedback drawer placeholder opened for ${escapeHtml(a.student)}.">Add feedback</button><button class="btn light small js-toast" data-toast="SmartTeacher AI practice generated from this assignment.">Create AI drill</button></div>
  </div>`;
}

function reportsSection(){
  return `<section class="section" id="reports">
    <div class="container section-head"><div><div class="eyebrow">Progress and completion reports</div><h2>Reports for students, teachers, employers, and staff.</h2></div><p>The platform should make progress visible: attendance, assignments, skill scores, CEFR level movement, credits used, completion status, and next recommendations.</p></div>
    <div class="container grid cols-2">
      ${studentReportCard()}
      ${employerReportCard()}
    </div>
  </section>`;
}
function studentReportCard(){
  const s = students[0];
  return `<article class="report-card" id="student-report">
    <div class="report-header"><div><img class="report-logo" src="assets/logo.svg" alt="EnglishLegalese"><h3>${s.name} — Progress Report</h3><p class="muted">Track: ${s.goal} · Teacher: ${s.teacher} · Current level: ${s.level}</p></div><span class="status gold">In progress</span></div>
    <div class="stat-grid"><div class="stat"><strong>${s.progress}%</strong><span>Overall progress</span></div><div class="stat"><strong>${s.attendance}%</strong><span>Attendance</span></div><div class="stat"><strong>${s.assignmentsDone}/${s.assignmentsTotal}</strong><span>Homework</span></div><div class="stat"><strong>${s.credits}</strong><span>Credits left</span></div></div>
    <h3 style="margin-top:18px">Skill movement</h3><div class="skill-grid"><div class="skill-item"><strong>Legal writing clarity</strong><div class="progress"><span style="width:72%"></span></div></div><div class="skill-item"><strong>Contract vocabulary</strong><div class="progress"><span style="width:64%"></span></div></div><div class="skill-item"><strong>Professional speaking</strong><div class="progress"><span style="width:56%"></span></div></div><div class="skill-item"><strong>Assignment completion</strong><div class="progress"><span style="width:71%"></span></div></div></div>
    <p class="clean-note"><strong>Next recommendation:</strong> Complete one client-update writing assignment, then move into mock class discussion and contract-clause explanation practice.</p>
    <button class="btn teal js-toast" data-toast="Student PDF progress report placeholder generated.">Generate student PDF</button>
  </article>`;
}
function employerReportCard(){
  return `<article class="report-card" id="employer-report">
    <div class="report-header"><div><img class="report-logo" src="assets/logo.svg" alt="EnglishLegalese"><h3>GlobalLex Partners — Employer Report</h3><p class="muted">Team 25 Credits · 12 employees · monthly report due July 31</p></div><span class="status green">Active</span></div>
    <div class="stat-grid"><div class="stat"><strong>18</strong><span>Credits left</span></div><div class="stat"><strong>61%</strong><span>Avg progress</span></div><div class="stat"><strong>88%</strong><span>Attendance</span></div><div class="stat"><strong>75%</strong><span>Homework completion</span></div></div>
    <div class="table-wrap"><table class="table"><tr><th>Employee</th><th>Track</th><th>Progress</th><th>Homework</th></tr>${students.slice(0,4).map(s=>`<tr><td>${s.name}</td><td>${s.goal}</td><td><div class="progress"><span style="width:${s.progress}%"></span></div></td><td>${s.assignmentsDone}/${s.assignmentsTotal}</td></tr>`).join('')}</table></div>
    <p class="clean-note"><strong>Manager summary:</strong> The group is improving most in vocabulary recognition. The next focus should be concise client updates, spoken confidence, and contract-obligation phrasing.</p>
    <button class="btn gold js-toast" data-toast="Employer completion report placeholder generated.">Generate employer report</button>
  </article>`;
}

function smartTeacherSection(){
  const tutorModes = [
    ['AI Writing Coach','Rewrite legal emails, memos, summaries, and client updates for clarity and tone.','Try a 120-word client update rewrite'],
    ['AI Speaking Tutor','Run mock client calls, negotiations, class discussions, and confidence drills.','Start a delayed-contract client roleplay'],
    ['AI Vocabulary Tutor','Practice contracts, litigation, compliance, TOLES, and business-law terminology.','Drill 10 contract obligation terms'],
    ['AI Homework Tutor','Guide students through teacher-assigned work without replacing teacher review.','Help me prepare my homework plan'],
    ['AI Teacher Assistant','Generate lesson plans, rubrics, homework, weak-area summaries, and follow-ups.','Create a 45-minute lesson plan'],
    ['AI Report Assistant','Draft student and employer progress summaries for staff/teacher review.','Summarize progress and next steps']
  ];
  return `<section class="section alt" id="smartteacher">
    <div class="container section-head"><div><div class="eyebrow">SmartTeacher AI tutor suite</div><h2>AI teachers, tutors, and teaching assistants — with human oversight.</h2></div><p>SmartTeacher AI supports language practice, homework, vocabulary, roleplay, writing clarity, teacher planning, and report drafting. It stays inside the language-education boundary.</p></div>
    <div class="container grid cols-2"><div>${aiAssistantBox()}</div><div class="card"><h3>Choose the right AI helper</h3><div class="ai-mode-grid">${tutorModes.map(m=>`<button class="ai-mode js-ai-prompt" data-prompt="${m[2]}"><strong>${m[0]}</strong><span>${m[1]}</span></button>`).join('')}</div><p class="notice"><strong>Boundary:</strong> AI can help with language, clarity, vocabulary, roleplay, and professional communication. It should not provide legal advice, legal strategy, or decide what a legal document means for a real case.</p></div></div>
  </section>`;
}

function pricingSection(){
  return `<section class="section" id="pricing">
    <div class="container section-head"><div><div class="eyebrow">Pricing</div><h2>Simple customer pricing. Controlled teacher payouts.</h2></div><p>V1.5 uses platform-set packages so students and employers buy EnglishLegalese programs, not the cheapest hourly teacher. Teacher pay is handled internally through approved payout tiers.</p></div>
    <div class="container grid cols-4">${packages.map(priceCard).join('')}</div>
    <div class="container notice" style="margin-top:18px"><strong>First operating model:</strong> EnglishLegalese collects payment first, assigns teachers, tracks completed lessons, then pays teachers from a controlled payout queue. This protects margins, quality, and brand positioning before full automatic marketplace payouts are built.</div>
  </section>`;
}
function priceCard(p){
  return `<article class="card ${p.type==='Employer'?'highlight':''}"><div class="kicker">${p.note} · ${p.type}</div><h3>${p.name}</h3><div class="price">${p.price}${p.suffix?` <small>${p.suffix}</small>`:''}</div><ul class="feature-list">${p.features.map(f=>`<li>${f}</li>`).join('')}</ul><button class="btn block js-toast" data-toast="${p.name} selected. Connect Stripe checkout or invoice workflow here.">${p.cta}</button></article>`;
}

function moneySection(){
  const gross = employers.reduce((a,e)=>a+e.monthlySpend,0) + 95 + 495 + 895 + 29*18 + 49*8;
  const privateCredits = 1 + 5 + 10;
  const avgPrivatePayout = 52;
  const estimatedPrivatePayouts = privateCredits * avgPrivatePayout;
  const firmDeliveryReserve = Math.round(employers.reduce((a,e)=>a+e.monthlySpend,0) * .48);
  const payouts = estimatedPrivatePayouts + firmDeliveryReserve;
  const margin = gross - payouts;
  const marginPct = Math.round((margin/gross)*100);
  return `<section class="section alt" id="money">
    <div class="container section-head"><div><div class="eyebrow">Money model</div><h2>How EnglishLegalese makes money without racing to the bottom.</h2></div><p>The platform starts with controlled public packages, employer credits, AI subscriptions, teacher-side upgrades, and teacher-sourced lead attribution. Teacher pay stays internal, tiered, and quality-controlled.</p></div>
    <div class="container money-grid"><div class="card"><h3>Recommended revenue flow</h3><ol class="revenue-flow"><li><div><strong>Free diagnostic captures the lead.</strong><p class="muted">Students and firms reveal their exact Legal English problem.</p></div></li><li><div><strong>Platform sells the package.</strong><p class="muted">Public prices are set by EnglishLegalese: assessment, 5-lesson, 10-lesson, employer credits, AI membership, or custom program.</p></div></li><li><div><strong>Teacher marketing can source the lead.</strong><p class="muted">Approved teachers share trackable profile links, class spotlights, QR codes, webinars, and employer intro pages.</p></div></li><li><div><strong>Admin assigns the teacher.</strong><p class="muted">The student sees a professional match, not a low-price bidding market.</p></div></li><li><div><strong>Teacher works under an approved tier.</strong><p class="muted">Standard, Specialist, or Lawyer/Advanced payouts are based on credentials, specialty, lesson type, and quality.</p></div></li><li><div><strong>Platform keeps margin and pays teacher.</strong><p class="muted">Payout releases after completion, attendance, teacher notes, homework/reports, and quality checks.</p></div></li></ol></div><div class="card"><h3>Prototype revenue dashboard</h3><div class="stat-grid" style="grid-template-columns:1fr 1fr"><div class="stat"><strong>$${gross.toLocaleString()}</strong><span>Tracked gross</span></div><div class="stat"><strong>$${payouts.toLocaleString()}</strong><span>Est. delivery payouts</span></div><div class="stat"><strong>$${margin.toLocaleString()}</strong><span>Platform margin</span></div><div class="stat"><strong>${marginPct}%</strong><span>Sample margin</span></div></div><ul class="feature-list"><li>Firm credits should become the main revenue driver</li><li>AI membership adds recurring income</li><li>Featured teacher listings add teacher-side revenue after approval</li><li>Teacher-sourced leads add lower-cost acquisition and bonus-driven growth</li><li>Completion reports help renew employer packages</li><li>Internal payout tiers protect brand positioning and margin</li></ul></div></div>
  </section>`;
}

function dashboardsPreview(){
  return `<section class="section" id="dashboards">
    <div class="container section-head"><div><div class="eyebrow">Dashboards</div><h2>Every role gets a useful operating center.</h2></div><p>Students, teachers, employers, and admin/staff each see the information they need without cluttering the experience for everyone else.</p></div>
    <div class="container role-tabs"><button class="js-role ${state.role==='student'?'active':''}" data-role="student">Student</button><button class="js-role ${state.role==='teacher'?'active':''}" data-role="teacher">Teacher</button><button class="js-role ${state.role==='employer'?'active':''}" data-role="employer">Employer</button><button class="js-role ${state.role==='admin'?'active':''}" data-role="admin">Owner/Admin</button></div>
    <div class="container" id="dashboardMount">${dashboardByRole(state.role)}</div>
  </section>`;
}
function renderDashboards(){ const mount=$('#dashboardMount'); if(mount){ mount.innerHTML=dashboardByRole(state.role); } $$('.js-role').forEach(b=>b.classList.toggle('active', b.dataset.role===state.role)); bindCommon(); }
function dashLayout(role, inner){ return `<div class="dashboard-shell"><aside class="dash-side"><h3>${role} Dashboard</h3><a class="active" href="#dashboards">Overview</a><a href="#teacher-growth">Teacher growth</a><a href="#classrooms">Classrooms</a><a href="#homework">Homework</a><a href="#reports">Reports</a><a href="#pricing">Billing</a><a href="#smartteacher">SmartTeacher AI</a><a href="#operations">Staff ops</a><button class="js-toast" data-toast="Settings saved in prototype mode.">Settings</button></aside><div class="dash-main">${inner}</div></div>`; }
function dashboardByRole(role){ if(role==='teacher') return teacherDashboard(); if(role==='employer') return employerDashboard(); if(role==='admin') return adminDashboard(); return studentDashboard(); }

function studentDashboard(){
  const s=students[0];
  return dashLayout('Student', `<div class="panel"><div class="panel-head"><div><h3>${s.name}</h3><p class="muted">Goal: ${s.goal} · Level ${s.level} · Teacher: ${s.teacher}</p></div><a class="btn teal" href="#classrooms">Enter classroom</a></div><div class="stat-grid"><div class="stat"><strong>${s.progress}%</strong><span>Path progress</span></div><div class="stat"><strong>${s.credits}</strong><span>Lesson credits</span></div><div class="stat"><strong>${s.assignmentsDone}/${s.assignmentsTotal}</strong><span>Homework</span></div><div class="stat"><strong>${s.attendance}%</strong><span>Attendance</span></div></div></div><div class="panel"><h3>My assignments</h3><div>${state.assignments.filter(a=>a.student===s.name).map(assignmentCard).join('') || '<p class="muted">No assignments assigned.</p>'}</div></div><div class="panel"><h3>Learning progress</h3><div class="table-wrap"><table class="table"><tr><th>Skill</th><th>Progress</th><th>Next action</th></tr><tr><td>Legal writing clarity</td><td><div class="progress"><span style="width:72%"></span></div></td><td>Revise client email</td></tr><tr><td>Contract vocabulary</td><td><div class="progress"><span style="width:64%"></span></div></td><td>Clause drill</td></tr><tr><td>Class discussion speaking</td><td><div class="progress"><span style="width:48%"></span></div></td><td>Mock seminar answer</td></tr></table></div></div><div class="panel"><h3>Completion report preview</h3>${studentReportCard()}</div><div class="panel"><h3>Next lesson checklist</h3><ul class="feature-list"><li>Complete assigned homework before the next classroom</li><li>Practice once with SmartTeacher AI</li><li>Bring one real writing sample or roleplay scenario</li><li>Review teacher corrections and next-step recommendations</li></ul></div>`);
}
