function renderStandaloneDashboard(role){ state.role=role; save(); pageShell(`${hero()}<section class="section" id="dashboards"><div class="container section-head"><div><div class="eyebrow">Dashboard</div><h2>${role[0].toUpperCase()+role.slice(1)} dashboard.</h2></div><p>Role-specific workflow for the first EnglishLegalese operating platform.</p></div><div class="container role-tabs"><button class="js-role ${role==='student'?'active':''}" data-role="student">Student</button><button class="js-role ${role==='teacher'?'active':''}" data-role="teacher">Teacher</button><button class="js-role ${role==='employer'?'active':''}" data-role="employer">Employer</button><button class="js-role ${role==='admin'?'active':''}" data-role="admin">Owner/Admin</button></div><div class="container" id="dashboardMount">${dashboardByRole(role)}</div></section>`); }
function renderClassroomPage(){ pageShell(`${hero()}${classroomsSection()}${homeworkSection()}${reportsSection()}${dashboardsPreview()}`); }

function route(){
  const h = location.hash.replace('#','') || 'home';
  if(['student-dashboard','teacher-dashboard','employer-dashboard','admin-dashboard'].includes(h)) return renderStandaloneDashboard(h.replace('-dashboard',''));
  if(h==='classrooms' || h==='homework' || h==='reports') { renderClassroomPage(); setTimeout(()=>{ const el=document.getElementById(h); if(el) el.scrollIntoView({behavior:'smooth', block:'start'});},40); return; }
  home();
  setTimeout(()=>{ const el=document.getElementById(h); if(el && h!=='home') el.scrollIntoView({behavior:'smooth', block:'start'});},40);
}


function captureLead(form){
  const area = form.closest('article')?.id || 'lead';
  const inputs = Array.from(form.querySelectorAll('input, select, textarea'));
  const first = inputs.find(i=>i.value && i.value.trim())?.value?.trim() || 'New inquiry';
  let type='Student', value='$495–$895', status='New';
  if(area.includes('firm')){ type='Firm'; value='$2,250+'; status='Proposal'; }
  if(area.includes('teacher')){ type='Teacher'; value='Tier + growth review'; status='Review'; }
  const need = inputs.map(i=>i.value).filter(Boolean).slice(1,3).join(' · ') || 'Needs follow-up';
  state.leads.unshift({type,name:first,need,value,status});
  save();
}

function bindCommon(){
  $$('.js-toast').forEach(btn=>btn.addEventListener('click',()=>toast(btn.dataset.toast || 'Saved.')));
  $$('.js-role').forEach(btn=>btn.addEventListener('click',()=>{state.role=btn.dataset.role; save(); renderDashboards();}));
  $$('.js-classroom').forEach(btn=>btn.addEventListener('click',()=>{state.classroom=btn.dataset.classroom; save(); const mount=$('#classrooms'); if(mount){ mount.outerHTML=classroomsSection(); bindCommon(); document.getElementById('classrooms')?.scrollIntoView({behavior:'smooth'}); }}));
  $$('.js-form').forEach(form=>form.addEventListener('submit',e=>{ e.preventDefault(); const area=form.closest('article')?.id || ''; if(['student-intake','firm-intake','teacher-apply'].includes(area)) captureLead(form); toast(form.dataset.success || 'Saved.'); form.reset(); }));
  $$('.js-scroll-homework').forEach(btn=>btn.addEventListener('click',()=>document.getElementById('homework')?.scrollIntoView({behavior:'smooth'})));
  $$('.js-scroll-report').forEach(btn=>btn.addEventListener('click',()=>{toast('Report draft generated.'); document.getElementById('reports')?.scrollIntoView({behavior:'smooth'});}));
  $$('.js-complete').forEach(btn=>btn.addEventListener('click',()=>{ const item=state.assignments.find(a=>a.id===btn.dataset.id); if(item){ item.status='Completed'; item.score=item.score || 90; save(); toast('Assignment marked complete. Progress reports updated.'); const list=$('#assignmentList'); if(list) list.innerHTML=assignmentList(); renderDashboards(); } }));
  const assignmentForm=$('#assignmentForm');
  if(assignmentForm){ assignmentForm.addEventListener('submit', e=>{ e.preventDefault(); const newItem={id:'a'+Date.now(), student:$('#hwStudent').value, employer: $('#hwStudent').value.includes('Cohort')?'GlobalLex Partners':'Individual', title:$('#hwTitle').value || 'Legal English assignment', track:$('#hwTrack').value, due:$('#hwDue').value || 'Next lesson', status:'Assigned', score:null, teacher:$('#hwTeacher').value, instructions:$('#hwInstructions').value || 'Complete the assignment and prepare to discuss it in the next lesson.'}; state.assignments.unshift(newItem); save(); $('#assignmentList').innerHTML=assignmentList(); assignmentForm.reset(); toast('Homework assigned. Student, teacher, employer, and admin reports updated.'); }); }
  const seed=$('#seedHomework');
  if(seed){ seed.addEventListener('click',()=>{ const sample={id:'a'+Date.now(), student:'GlobalLex Cohort A', employer:'GlobalLex Partners', title:'Group client-update writing drill', track:'Client calls', due:'July 20', status:'Assigned', score:null, teacher:'Maya Chen, JD', instructions:'Each employee writes a concise client update about a delayed contract review. Teacher reviews clarity, tone, and risk language.'}; state.assignments.unshift(sample); save(); $('#assignmentList').innerHTML=assignmentList(); bindCommon(); toast('Sample group homework added.'); }); }
  const reset=$('#resetHomework');
  if(reset){ reset.addEventListener('click',()=>{ state.assignments=[...baseAssignments]; save(); $('#assignmentList').innerHTML=assignmentList(); bindCommon(); toast('Demo assignments reset.'); }); }
  const send=$('#aiSend');
  if(send){ send.addEventListener('click', sendAi); const inp=$('#aiInput'); if(inp){ inp.addEventListener('keydown', e=>{ if(e.key==='Enter') sendAi(); }); } }
  $$('.js-ai-prompt').forEach(btn=>btn.addEventListener('click',()=>{ const input=$('#aiInput'); if(input){ input.value=btn.dataset.prompt; sendAi(); } }));
}
function sendAi(){
  const input=$('#aiInput'); const win=$('#chatWindow'); if(!input || !win || !input.value.trim()) return;
  const q=input.value.trim(); state.aiMessages.push({from:'user', text:q});
  const answer = smartTeacherAnswer(q);
  state.aiMessages.push({from:'ai', text:answer});
  input.value='';
  const box=$('#ai-box'); if(box){ box.outerHTML=aiAssistantBox(); bindCommon(); const w=$('#chatWindow'); if(w) w.scrollTop=w.scrollHeight; }
}
function smartTeacherAnswer(q){
  const lower=q.toLowerCase();
  if(lower.includes('email')) return 'Language practice: use a clear subject, one-sentence context, concise status, next step, and a polite close. Avoid giving legal advice. Try rewriting the email in 120 words, then I can help improve tone and clarity.';
  if(lower.includes('contract') || lower.includes('clause')) return 'Contract Legal English drill: define obligation, discretion, condition, representation, warranty, indemnity, and termination. Then write one plain-English sentence and one formal sentence for each term.';
  if(lower.includes('roleplay') || lower.includes('client')) return 'Client-call roleplay: I will act as a client asking for a status update. Your goal is to explain delay, next step, and expected timeline clearly, without overpromising. Start with: “Thank you for your patience…”';
  if(lower.includes('marketing') || lower.includes('linkedin') || lower.includes('referral') || lower.includes('campaign')) return 'Teacher marketing assistant draft: share your approved EnglishLegalese profile link, name one specific Legal English outcome, invite the reader to take the free diagnostic, and avoid quoting private lesson prices. Example CTA: “Take the Legal English diagnostic and request my class through EnglishLegalese.”';
  if(lower.includes('report') || lower.includes('progress')) return 'Report assistant draft: summarize attendance, homework completion, skill movement, teacher observation, next recommendation, and renewal risk. Keep employer reports professional and avoid exposing sensitive student notes unless authorized.';
  if(lower.includes('lesson plan') || lower.includes('teacher')) return 'Teacher assistant plan: begin with a 5-minute warm-up, 15-minute language focus, 15-minute legal communication task, 10-minute roleplay, and 5-minute homework briefing. Score clarity, accuracy, tone, and confidence.';
  if(lower.includes('homework') || lower.includes('assignment')) return 'Homework tutor idea: assign one short writing task, one vocabulary set, and one speaking prompt. Student can practice with AI, but teacher review remains the official feedback step.';
  return 'SmartTeacher AI suggestion: turn this into a Legal English practice task with vocabulary, a short writing exercise, a speaking roleplay, and one teacher-reviewed homework deliverable. This is language training only, not legal advice.';
}



