function productionBackendSection(){
  const routes = [
    ['Auth/login','/api/v119/auth/register + /login + /me','Real users, sessions, and role permissions.'],
    ['PostgreSQL','/db/migrations/002_auth_payments_integrations.sql','Additive migration for credentials, sessions, payments, webhooks, emails, AI, and integrations.'],
    ['Stripe','/api/v119/payments/create-checkout + /stripe/webhook','Platform collects payment first; webhook verifies raw-body signature.'],
    ['Uploads','/api/v119/uploads/presign','S3-compatible presigned uploads for homework, saved work, and reports.'],
    ['Calendar/video','/api/v119/calendar-video/create-session','Google Meet by default, Zoom as approved alternate, Teams later.'],
    ['Reports + AI','/api/v119/reports/pdf + /smartteacher','Server-side PDF reports and SmartTeacher AI route with safe Legal-English-only boundary.']
  ];
  return `<section class="section" id="production-backend">
    <div class="container section-head"><div><div class="eyebrow">Production backend foundation</div><h2>Now the platform has the backend structure needed to preserve real users, classes, payments, uploads, reports, and AI work across future deployments.</h2></div><p>This is the practical next layer behind the branded experience: accounts, permissions, database migrations, object storage, payment webhooks, calendar/video sessions, email, PDF reports, and server-side SmartTeacher AI.</p></div>
    <div class="container grid cols-3">${routes.map(([name,path,desc])=>`<article class="card"><div class="kicker">${name}</div><h3>${path}</h3><p>${desc}</p></article>`).join('')}</div>
    <div class="container panel" style="margin-top:18px"><div class="panel-head"><div><h3>Safe deployment rule</h3><p class="muted">Deploy code only. Never overwrite PostgreSQL records, object storage files, Stripe history, calendar/video IDs, saved homework, reports, teacher payouts, employer records, or audit logs.</p></div><button class="btn teal js-toast" data-toast="Production readiness check endpoint: /api/v119/production-readiness">Check readiness</button></div><div class="grid cols-4"><article class="mini"><strong>Before launch</strong><span>Set real credentials and run migrations on managed PostgreSQL.</span></article><article class="mini"><strong>Before each deploy</strong><span>Run predeploy checks and keep database/object storage outside the ZIP.</span></article><article class="mini"><strong>After deploy</strong><span>Smoke test login, sessions, saved work, payments, calendar, reports, and AI.</span></article><article class="mini"><strong>If blocked</strong><span>Do not accept users until production readiness shows required services configured.</span></article></div></div>
  </section>`;
}

