function teacherMarketingSection(){
  const totalLeads = teacherCampaigns.reduce((a,c)=>a+c.leads,0);
  const totalConverted = teacherCampaigns.reduce((a,c)=>a+c.converted,0);
  const totalRevenue = teacherCampaigns.reduce((a,c)=>a+c.revenue,0);
  const totalBonus = teacherCampaigns.reduce((a,c)=>a+c.bonus,0);
  return `<section class="section" id="teacher-growth">
    <div class="container section-head"><div><div class="eyebrow">Teacher marketing toolkit</div><h2>Give teachers growth tools without turning the platform into a price-shopping marketplace.</h2></div><p>Teachers can promote their expertise from LinkedIn, email, WhatsApp, webinars, universities, translator groups, and employer contacts. EnglishLegalese still controls pricing, checkout, credits, quality review, and reports.</p></div>
    <div class="container grid cols-2">
      <article class="card highlight"><h3>Simple growth rules</h3><ul class="feature-list">${marketingRules.map(rule=>`<li>${rule}</li>`).join('')}</ul><p class="clean-note"><strong>Operating principle:</strong> teacher marketing creates demand; EnglishLegalese converts, invoices, matches, tracks, reports, and pays.</p></article>
      <article class="card"><h3>Teacher-sourced revenue dashboard</h3><div class="stat-grid" style="grid-template-columns:1fr 1fr"><div class="stat"><strong>${totalLeads}</strong><span>Tracked leads</span></div><div class="stat"><strong>${totalConverted}</strong><span>Conversions</span></div><div class="stat"><strong>$${totalRevenue.toLocaleString()}</strong><span>Revenue influenced</span></div><div class="stat"><strong>$${totalBonus.toLocaleString()}</strong><span>Marketing bonuses</span></div></div><p class="notice"><strong>Suggested bonus policy:</strong> $25 for converted individual package leads, $50 for Professional 10, and 3%–5% of first employer package up to a staff-approved cap. Bonus is paid only after attribution, payment, and no off-platform diversion.</p></article>
    </div>
    <div class="container grid cols-3" style="margin-top:18px">${marketingAssets.map(marketingAssetCard).join('')}</div>
    <div class="container panel" style="margin-top:18px"><div class="panel-head"><div><h3>Approved social and outreach templates</h3><p class="muted">These give teachers fast, safe copy they can use from their own accounts while keeping price, checkout, and claims under EnglishLegalese control.</p></div><button class="btn gold js-toast" data-toast="Teacher campaign draft sent to admin approval queue.">Submit campaign</button></div><div class="grid cols-4">${v15TeacherTemplates.map(t=>`<article class="template-card"><div class="kicker">${t.channel}</div><h3>${t.title}</h3><p>${t.copy}</p><button class="btn light small js-toast" data-toast="${t.title} copied with tracking link placeholder.">${t.cta}</button></article>`).join('')}</div></div>
    <div class="container panel" style="margin-top:18px"><div class="panel-head"><div><h3>Campaign tracking and approval</h3><p class="muted">Staff sees what each teacher is promoting, which leads converted, and whether a claim needs review before more sharing.</p></div><button class="btn light js-toast" data-toast="Campaign review checklist opened.">Open review checklist</button></div><div class="table-wrap"><table class="table"><tr><th>Teacher</th><th>Code</th><th>Channel</th><th>Focus</th><th>Leads</th><th>Converted</th><th>Revenue</th><th>Bonus</th><th>Status</th></tr>${teacherCampaigns.map(c=>`<tr><td>${c.teacher}</td><td><strong>${c.code}</strong></td><td>${c.channel}</td><td>${c.focus}</td><td>${c.leads}</td><td>${c.converted}</td><td>$${c.revenue.toLocaleString()}</td><td>$${c.bonus}</td><td><span class="status ${c.status==='Active'?'green':c.status==='Paused'?'gray':'gold'}">${c.status}</span></td></tr>`).join('')}</table></div></div>
  </section>`;
}

