function aiAssistantBox(compact=false){
  return `<div class="ai-box" id="ai-box"><div class="panel-head" style="margin-bottom:8px"><div><h3>SmartTeacher AI</h3><p class="muted" style="margin:0">Language practice only — not legal advice.</p></div></div>
    <div class="ai-context-row"><span>Student tutor</span><span>Teacher assistant</span><span>Employer report helper</span></div>
    <div class="chat-window" id="chatWindow">${state.aiMessages.map(m=>`<div class="bubble ${m.from==='ai'?'ai':'user'}">${escapeHtml(m.text)}</div>`).join('')}</div>
    <div class="input-row"><input id="aiInput" placeholder="Ask for a vocabulary drill, email rewrite, report note, or teacher lesson plan..." /><button class="btn teal" id="aiSend">Send</button></div>
    <div class="tag-row"><button class="btn light small js-ai-prompt" data-prompt="Create a Legal English homework drill about contract obligations.">Contract drill</button><button class="btn light small js-ai-prompt" data-prompt="Help me rewrite a client email in concise Legal English.">Email rewrite</button><button class="btn light small js-ai-prompt" data-prompt="Create a teacher lesson plan and closeout checklist.">Teacher plan</button>${compact?'':`<button class="btn light small js-ai-prompt" data-prompt="Draft a safe employer progress report summary.">Report summary</button><button class="btn light small js-ai-prompt" data-prompt="Create a LinkedIn post for a Legal English teacher without mentioning private prices.">Marketing post</button>`}</div>
  </div>`;
}

function homeworkSection(){
  const templates = [
    ['Client update email','Legal writing','120 words; status, issue, next step, professional tone.'],
    ['Contract vocabulary drill','Contracts','Define 10 terms and write formal/plain-English examples.'],
    ['Mock client call script','Speaking','Practice status, timeline, risk language, and polite confidence.'],
    ['TOLES clause practice','TOLES','Explain clause meaning and identify key legal-English signals.']
  ];
  return `<section class="section alt" id="homework">
    <div class="container section-head"><div><div class="eyebrow">Homework assignments</div><h2>Homework turns lessons into measurable progress.</h2></div><p>Students practice between classes. Teachers assign and score work. Employers see completion and skill movement without seeing sensitive private notes unnecessarily. Staff can audit the whole queue.</p></div>
    <div class="container grid cols-2">
      <div class="panel" style="margin-bottom:0">
        <div class="panel-head"><div><h3>Create assignment</h3><p class="muted">Teacher-created homework connects live lessons to daily practice.</p></div></div>
        <div class="template-row">${templates.map(t=>`<button class="template-chip js-toast" data-toast="${t[0]} template selected."><strong>${t[0]}</strong><span>${t[1]} · ${t[2]}</span></button>`).join('')}</div>
        <form class="form-grid" id="assignmentForm">
          <div class="field"><label>Student / cohort</label><select id="hwStudent">${students.map(s=>`<option>${s.name}</option>`).join('')}<option>GlobalLex Cohort A</option></select></div>
          <div class="field"><label>Track</label><select id="hwTrack"><option>Legal writing</option><option>Contracts</option><option>TOLES Advanced</option><option>Client calls</option><option>Compliance</option><option>Negotiation</option></select></div>
          <div class="field span-2"><label>Assignment title</label><input id="hwTitle" required placeholder="Example: Rewrite a client status update"></div>
          <div class="field"><label>Due date</label><input id="hwDue" type="date"></div>
          <div class="field"><label>Teacher</label><select id="hwTeacher">${teachers.filter(t=>t.status==='Approved').map(t=>`<option>${t.name}</option>`).join('')}</select></div>
          <div class="field span-2"><label>Instructions</label><textarea id="hwInstructions" placeholder="Give clear instructions, word count, vocabulary goals, allowed AI practice, and teacher review criteria."></textarea></div>
          <button class="btn gold" type="submit">Assign homework</button><button class="btn light" type="button" id="seedHomework">Add sample assignment</button>
        </form>
      </div>
      <div class="panel" style="margin-bottom:0">
        <div class="panel-head"><div><h3>Assignment queue</h3><p class="muted">One queue powers student, teacher, employer, and admin views.</p></div><button class="btn light small" id="resetHomework">Reset demo</button></div>
        <div class="assignment-summary"><span>${state.assignments.length} total</span><span>${state.assignments.filter(a=>a.status==='Submitted'||a.status==='Needs Revision').length} need review</span><span>${state.assignments.filter(a=>a.status==='Assigned').length} assigned</span></div>
        <div id="assignmentList">${assignmentList()}</div>
      </div>
    </div>
  </section>`;
}

