function employerDashboard(){
  const e=employers[0];
  return dashLayout('Employer', `<div class="panel"><div class="panel-head"><div><h3>${e.name}</h3><p class="muted">${e.plan} · ${e.employees} employees · ${e.status}</p></div><button class="btn gold js-toast" data-toast="Firm credit top-up checkout placeholder selected.">Buy more credits</button></div><div class="stat-grid"><div class="stat"><strong>${e.creditBalance}</strong><span>Credits left</span></div><div class="stat"><strong>${e.employees}</strong><span>Employees</span></div><div class="stat"><strong>${e.progress}%</strong><span>Avg progress</span></div><div class="stat"><strong>${e.reportDue}</strong><span>Report due</span></div></div></div><div class="panel"><h3>Employer next actions</h3><div class="next-actions"><a href="#reports">Review monthly report</a><a href="#pricing">Top up credits</a><a href="#classrooms">View group classroom</a><a href="#firm-intake">Add employees</a></div></div><div class="panel"><h3>Employee progress and homework</h3><div class="table-wrap"><table class="table"><tr><th>Employee</th><th>Track</th><th>Progress</th><th>Attendance</th><th>Homework</th><th>Status</th></tr>${students.map(s=>`<tr><td>${s.name}</td><td>${s.goal}</td><td><div class="progress"><span style="width:${s.progress}%"></span></div></td><td>${s.attendance}%</td><td>${s.assignmentsDone}/${s.assignmentsTotal}</td><td><span class="status green">Active</span></td></tr>`).join('')}</table></div></div><div class="panel"><h3>Manager report</h3><p class="muted">Top team needs: concise client updates, contract definitions, negotiation phrases, and spoken confidence in cross-border calls.</p><div class="tag-row"><button class="btn teal js-toast" data-toast="Monthly employer report generated.">Generate monthly report</button><button class="btn light js-toast" data-toast="Employee CSV export placeholder generated.">Export employee CSV</button></div></div><div class="panel"><h3>Employer privacy view</h3><p class="muted">Managers see attendance, completion, skill movement, and recommendations. Sensitive student homework text and personal learning notes stay limited to the student, teacher, and authorized staff.</p></div>`);
}

function adminDashboard(){
  const gross = employers.reduce((a,e)=>a+e.monthlySpend,0)+95+495+895+29*18+49*8;
  const teacherPayout = Math.round(gross*.47);
  const margin = gross-teacherPayout;
  const dueReviews = state.assignments.filter(a=>a.status==='Submitted' || a.status==='Needs Revision').length;
  return dashLayout('Owner/Admin', `<div class="panel"><div class="panel-head"><div><h3>Platform command center</h3><p class="muted">Revenue, approvals, classrooms, credits, payouts, homework, reports, campaigns, and quality controls.</p></div><button class="btn gold js-toast" data-toast="Admin export generated.">Export CSV</button></div><div class="stat-grid"><div class="stat"><strong>$${gross.toLocaleString()}</strong><span>Tracked gross sales</span></div><div class="stat"><strong>$${teacherPayout.toLocaleString()}</strong><span>Est. teacher payouts</span></div><div class="stat"><strong>$${margin.toLocaleString()}</strong><span>Est. platform margin</span></div><div class="stat"><strong>${dueReviews}</strong><span>Homework reviews due</span></div><div class="stat"><strong>3</strong><span>Employer accounts</span></div></div></div><div class="panel"><h3>Owner/staff next actions</h3><div class="next-actions"><a href="#operations">Open lead queue</a><a href="#teacher-growth">Review campaigns</a><a href="#reports">Clear report queue</a><a href="#pricing">Check revenue lanes</a></div></div><div class="panel"><h3>Teacher approval and payout tiers</h3><div class="table-wrap"><table class="table"><tr><th>Name</th><th>Specialty</th><th>Tier</th><th>Private payout</th><th>Status</th><th>Action</th></tr>${teachers.map(t=>`<tr><td>${t.name}</td><td>${t.specialties.slice(0,2).join(', ')}</td><td>${t.payoutTier}</td><td>$${t.privatePayout || 0}</td><td><span class="status ${t.status==='Approved'?'green':'gold'}">${t.status}</span></td><td><button class="btn light small js-toast" data-toast="${t.name} payout tier reviewed.">Review tier</button></td></tr>`).join('')}</table></div></div><div class="panel"><h3>Reports due and renewal opportunities</h3><div class="table-wrap"><table class="table"><tr><th>Employer</th><th>Credits</th><th>Report due</th><th>Renewal</th><th>Action</th></tr>${employers.map(e=>`<tr><td>${e.name}</td><td>${e.creditBalance}</td><td>${e.reportDue}</td><td>${e.renewal}</td><td><button class="btn light small js-toast" data-toast="Renewal task created for ${e.name}.">Create task</button></td></tr>`).join('')}</table></div></div><div class="panel"><h3>Lead queue</h3>${leadQueueTable()}</div><div class="panel"><h3>Teacher campaign approvals</h3><div class="table-wrap"><table class="table"><tr><th>Teacher</th><th>Campaign</th><th>Leads</th><th>Revenue</th><th>Status</th><th>Action</th></tr>${teacherCampaigns.map(c=>`<tr><td>${c.teacher}</td><td>${c.focus}</td><td>${c.leads}</td><td>$${c.revenue.toLocaleString()}</td><td><span class="status ${c.status==='Active'?'green':c.status==='Paused'?'gray':'gold'}">${c.status}</span></td><td><button class="btn light small js-toast" data-toast="Campaign reviewed for ${c.teacher}.">Review</button></td></tr>`).join('')}</table></div></div>`);
}


