brand.version = 'v1.6.0 Saved Work + Exams Continuity Polish';

const savedWorkItems = [
  {id:'w1', owner:'Ana Kowalska', employer:'GlobalLex Partners', type:'Homework draft', title:'Client update email revision', status:'Draft saved', lastSaved:'Today 10:42 AM', next:'Submit for teacher review', privacy:'Student + teacher + staff'},
  {id:'w2', owner:'Marco Silva', employer:'GlobalLex Partners', type:'Classwork', title:'Negotiation phrase bank', status:'In progress', lastSaved:'Yesterday 4:15 PM', next:'Finish during group class', privacy:'Student + teacher'},
  {id:'w3', owner:'Hana Park', employer:'Northstar Compliance', type:'AI practice note', title:'Compliance memo vocabulary drill', status:'Needs teacher review', lastSaved:'Jul 8, 2:30 PM', next:'Teacher comments due', privacy:'Student + teacher + authorized staff'},
  {id:'w4', owner:'GlobalLex Cohort A', employer:'GlobalLex Partners', type:'Group classwork', title:'Client status-update templates', status:'Shared cohort workspace', lastSaved:'Jul 7, 5:10 PM', next:'Manager summary only', privacy:'Cohort + teacher + employer summary'}
];

const examItems = [
  {id:'x1', name:'Legal English Placement Diagnostic', audience:'New students', status:'Available', length:'20–25 min', score:'Baseline', review:'AI score + staff/teacher path recommendation'},
  {id:'x2', name:'Contract Vocabulary Progress Check', audience:'Active students', status:'In progress', length:'15 min', score:'62% saved', review:'Teacher reviews weak terms before next lesson'},
  {id:'x3', name:'Employer Team Midpoint Assessment', audience:'Firm cohorts', status:'Scheduled', length:'30 min', score:'Pending', review:'Employer receives aggregate progress report'},
  {id:'x4', name:'Completion Assessment + Certificate Review', audience:'Students / teams', status:'Locked until requirements met', length:'30–40 min', score:'Requires 80% + teacher signoff', review:'Completion report and certificate decision'}
];

const continuityStandards = [
  'Every homework assignment should have Draft, Submitted, Needs Revision, Reviewed, and Completed states.',
  'Classwork-in-progress should autosave locally in the prototype and later save to each user account in the database.',
  'Exams should be resumable so a student or cohort does not lose work if interrupted.',
  'Teachers see student drafts only when submitted or shared for review; employers see completion and aggregate progress, not private notes.',
  'Staff sees overdue drafts, exams in progress, reports due, credit usage, and teacher review bottlenecks from one queue.'
];

function continuitySection(){
  return `<section class="section compact" id="continuity">
    <div class="container grid cols-4">
      <article class="card flat"><div class="kicker">Saved work</div><h3>Students do not lose progress.</h3><p>Homework drafts, classwork notes, AI practice outputs, and exam answers can be saved, resumed, submitted, reviewed, or completed.</p></article>
      <article class="card flat"><div class="kicker">Teacher clarity</div><h3>Teachers know what needs review.</h3><p>Submitted homework, drafts shared for help, classwork notes, and exam results feed a simple review queue.</p></article>
      <article class="card flat"><div class="kicker">Employer trust</div><h3>Employers see progress, not private notes.</h3><p>Firm dashboards show attendance, completion, scores, credits, risk flags, and recommendations without exposing sensitive student text.</p></article>
      <article class="card flat"><div class="kicker">Staff control</div><h3>Unfinished work becomes visible.</h3><p>Admin can see stuck drafts, overdue assignments, in-progress exams, reports due, renewals, and payout blockers.</p></article>
    </div>
  </section>`;
}

function savedWorkSection(){
  return `<section class="section" id="saved-work">
    <div class="container section-head"><div><div class="eyebrow">Saved homework and classwork</div><h2>Work-in-progress is now part of the product.</h2></div><p>Legal English learning is not just live class time. Students need to save drafts, return to assignments, keep class notes, resume AI practice, and submit polished work for teacher review.</p></div>
    <div class="container grid cols-2">
      <article class="panel"><div class="panel-head"><div><h3>Saved work queue</h3><p class="muted">A simple continuity view for students, teachers, employers, and staff.</p></div><button class="btn gold js-toast" data-toast="New draft created in prototype mode.">New draft</button></div><div class="table-wrap"><table class="table"><tr><th>Owner</th><th>Type</th><th>Work item</th><th>Status</th><th>Last saved</th><th>Next</th></tr>${savedWorkItems.map(w=>`<tr><td>${w.owner}</td><td>${w.type}</td><td>${w.title}</td><td><span class="status ${w.status.includes('Needs')?'gold':w.status.includes('Draft')?'gray':'green'}">${w.status}</span></td><td>${w.lastSaved}</td><td>${w.next}</td></tr>`).join('')}</table></div></article>
      <article class="panel"><h3>Student workspace prototype</h3><p class="muted">This shows the intended saved-draft flow before real accounts and database storage are connected.</p><form class="form-grid js-form" data-success="Classwork draft autosaved. Student can resume, submit, or request teacher review."><div class="field span-2"><label>Work type</label><select><option>Homework draft</option><option>Class notes</option><option>AI practice output</option><option>Exam notes</option></select></div><div class="field span-2"><label>Title</label><input placeholder="Example: Contract negotiation phrases"></div><div class="field span-2"><label>Draft / classwork</label><textarea placeholder="Write or paste Legal English work in progress here..."></textarea></div><div class="field"><label>Share with teacher?</label><select><option>Save privately</option><option>Submit for teacher review</option><option>Ask AI tutor first</option></select></div><div class="field"><label>Status</label><select><option>Draft saved</option><option>Submitted</option><option>Needs revision</option><option>Completed</option></select></div><button class="btn teal" type="submit">Save work</button><button class="btn light js-toast" type="button" data-toast="Draft submitted for teacher review.">Submit for review</button></form><p class="notice"><strong>Production rule:</strong> saved work should use authenticated accounts, timestamps, version history, and role-based privacy before launch.</p></article>
    </div>
    <div class="container grid cols-5" style="margin-top:18px">${continuityStandards.map(s=>`<article class="quality-note">${s}</article>`).join('')}</div>
  </section>`;
}

function examsSection(){
  return `<section class="section alt" id="exams">
    <div class="container section-head"><div><div class="eyebrow">Assessments and exams</div><h2>Placement, progress checks, and completion exams should be resumable.</h2></div><p>Exams create trust and measurable outcomes. They should support student placement, teacher planning, employer reporting, and certificate decisions without becoming complicated.</p></div>
    <div class="container grid cols-2">
      <article class="panel"><div class="panel-head"><div><h3>Exam and assessment queue</h3><p class="muted">Prototype statuses for students, teachers, employers, and staff.</p></div><button class="btn gold js-toast" data-toast="Exam invite link created.">Create exam link</button></div><div class="table-wrap"><table class="table"><tr><th>Assessment</th><th>Audience</th><th>Status</th><th>Time</th><th>Score</th><th>Review</th></tr>${examItems.map(x=>`<tr><td>${x.name}</td><td>${x.audience}</td><td><span class="status ${x.status.includes('In progress')?'gold':x.status.includes('Locked')?'gray':'green'}">${x.status}</span></td><td>${x.length}</td><td>${x.score}</td><td>${x.review}</td></tr>`).join('')}</table></div></article>
      <article class="panel"><h3>Exam-in-progress prototype</h3><p class="muted">A simple interface for saved answers, checkpoints, and review handoff.</p><div class="exam-progress"><div><strong>Contract Vocabulary Progress Check</strong><span>Question 7 of 12 · autosaved 2 minutes ago</span></div><div class="progress"><span style="width:58%"></span></div></div><form class="form-grid js-form" data-success="Exam answer saved. Student can resume later or submit when complete."><div class="field span-2"><label>Question</label><textarea readonly>Explain the difference between “shall,” “may,” “condition precedent,” and “best efforts” in practical Legal English.</textarea></div><div class="field span-2"><label>Saved answer</label><textarea placeholder="Student answer saved in progress..."></textarea></div><div class="field"><label>Confidence</label><select><option>Low</option><option>Medium</option><option>High</option></select></div><div class="field"><label>Action</label><select><option>Save and continue later</option><option>Ask SmartTeacher for language practice</option><option>Submit exam</option></select></div><button class="btn teal" type="submit">Save exam progress</button><button class="btn light js-toast" type="button" data-toast="Exam submitted for teacher/staff review.">Submit exam</button></form><p class="clean-note"><strong>Certificate rule:</strong> completion should require lesson/credit threshold, homework completion, exam score, and teacher or staff signoff.</p></article>
    </div>
  </section>`;
}

function home(){
  pageShell(`${hero()}${startSection()}${trustSection()}${continuitySection()}${v15ConversionSnapshotSection()}${pricingStrategySection()}${programsSection()}${diagnosticBuilderSection()}${workflowSection()}${teachersSection()}${teacherMarketingSection()}${classroomsSection()}${savedWorkSection()}${homeworkSection()}${examsSection()}${reportsSection()}${smartTeacherSection()}${operationsSection()}${pricingSection()}${moneySection()}${dashboardsPreview()}${formsSection()}${brandSection()}`);
}

