function adminDashboard(){
  const gross = employers.reduce((a,e)=>a+e.monthlySpend,0)+95+495+895+29*18+49*8;
  const teacherPayout = Math.round(gross*.47);
  const margin = gross-teacherPayout;
  const dueReviews = state.assignments.filter(a=>a.status==='Submitted' || a.status==='Needs Revision').length;
  return dashLayout('Owner/Admin', `<div class="panel"><div class="panel-head"><div><h3>Platform command center</h3><p class="muted">Revenue, approvals, classrooms, credits, payouts, saved work, exams, reports, campaigns, and quality controls.</p></div><button class="btn gold js-toast" data-toast="Admin export generated.">Export CSV</button></div><div class="stat-grid"><div class="stat"><strong>$${gross.toLocaleString()}</strong><span>Tracked gross sales</span></div><div class="stat"><strong>$${teacherPayout.toLocaleString()}</strong><span>Est. teacher payouts</span></div><div class="stat"><strong>$${margin.toLocaleString()}</strong><span>Est. platform margin</span></div><div class="stat"><strong>${dueReviews}</strong><span>Homework reviews due</span></div><div class="stat"><strong>1</strong><span>Exam in progress</span></div></div></div><div class="panel"><h3>Owner/staff next actions</h3><div class="next-actions"><a href="#operations">Open command center</a><a href="#saved-work">Check saved work</a><a href="#exams">Check exams</a><a href="#reports">Clear report queue</a></div></div><div class="panel"><h3>Saved work and exam blockers</h3><div class="table-wrap"><table class="table"><tr><th>Item</th><th>Owner</th><th>Status</th><th>Privacy</th><th>Next</th></tr>${savedWorkItems.map(w=>`<tr><td>${w.title}</td><td>${w.owner}</td><td>${w.status}</td><td>${w.privacy}</td><td>${w.next}</td></tr>`).join('')}${examItems.map(x=>`<tr><td>${x.name}</td><td>${x.audience}</td><td>${x.status}</td><td>Exam answers restricted</td><td>${x.review}</td></tr>`).join('')}</table></div></div><div class="panel"><h3>Teacher approval and payout tiers</h3><div class="table-wrap"><table class="table"><tr><th>Name</th><th>Specialty</th><th>Tier</th><th>Private payout</th><th>Status</th><th>Action</th></tr>${teachers.map(t=>`<tr><td>${t.name}</td><td>${t.specialties.slice(0,2).join(', ')}</td><td>${t.payoutTier}</td><td>$${t.privatePayout || 0}</td><td><span class="status ${t.status==='Approved'?'green':'gold'}">${t.status}</span></td><td><button class="btn light small js-toast" data-toast="${t.name} payout tier reviewed.">Review tier</button></td></tr>`).join('')}</table></div></div><div class="panel"><h3>Lead queue</h3>${leadQueueTable()}</div><div class="panel"><h3>Teacher campaign approvals</h3><div class="table-wrap"><table class="table"><tr><th>Teacher</th><th>Campaign</th><th>Leads</th><th>Revenue</th><th>Status</th><th>Action</th></tr>${teacherCampaigns.map(c=>`<tr><td>${c.teacher}</td><td>${c.focus}</td><td>${c.leads}</td><td>$${c.revenue.toLocaleString()}</td><td><span class="status ${c.status==='Active'?'green':c.status==='Paused'?'gray':'gold'}">${c.status}</span></td><td><button class="btn light small js-toast" data-toast="Campaign reviewed for ${c.teacher}.">Review</button></td></tr>`).join('')}</table></div></div>`);
}

