function adminDashboard(){
  const gross = employers.reduce((a,e)=>a+e.monthlySpend,0)+95+495+895+29*18+49*8;
  const teacherPayout = Math.round(gross*.47);
  const margin = gross-teacherPayout;
  const dueReviews = state.assignments.filter(a=>a.status==='Submitted' || a.status==='Needs Revision').length;
  return dashLayout('Owner/Admin', `<div class="panel today-panel"><div class="panel-head"><div><h3>Today for owner/staff</h3><p class="muted">Revenue, lead routing, teacher campaigns, classrooms, homework, exams, reports, payouts, and quality controls.</p></div><button class="btn gold js-toast" data-toast="Admin export generated.">Export CSV</button></div><div class="stat-grid"><div class="stat"><strong>$${gross.toLocaleString()}</strong><span>Tracked gross sales</span></div><div class="stat"><strong>$${teacherPayout.toLocaleString()}</strong><span>Est. teacher payouts</span></div><div class="stat"><strong>$${margin.toLocaleString()}</strong><span>Est. platform margin</span></div><div class="stat"><strong>${dueReviews}</strong><span>Homework reviews due</span></div></div></div><div class="panel"><h3>One next best action</h3><div class="next-best"><strong>Clear the daily staff triage board.</strong><span>Focus first on firm proposal, teacher campaign approvals, homework reviews, missing closeouts, employer report, and payout holds.</span><a class="btn teal" href="#operations">Open operations</a></div></div><div class="panel"><h3>Saved work, exams, and report blockers</h3><div class="table-wrap"><table class="table"><tr><th>Item</th><th>Owner</th><th>Status</th><th>Privacy</th><th>Next</th></tr>${savedWorkItems.map(w=>`<tr><td>${w.title}</td><td>${w.owner}</td><td>${w.status}</td><td>${w.privacy}</td><td>${w.next}</td></tr>`).join('')}${examItems.map(x=>`<tr><td>${x.name}</td><td>${x.audience}</td><td>${x.status}</td><td>Exam answers restricted</td><td>${x.review}</td></tr>`).join('')}</table></div></div><div class="panel"><h3>Teacher campaigns and payout tiers</h3><div class="table-wrap"><table class="table"><tr><th>Teacher</th><th>Campaign / specialty</th><th>Tier</th><th>Revenue</th><th>Status</th><th>Action</th></tr>${teachers.map((t,i)=>`<tr><td>${t.name}</td><td>${teacherCampaigns[i%teacherCampaigns.length].focus}</td><td>${t.payoutTier}</td><td>$${teacherCampaigns[i%teacherCampaigns.length].revenue.toLocaleString()}</td><td><span class="status ${t.status==='Approved'?'green':'gold'}">${t.status}</span></td><td><button class="btn light small js-toast" data-toast="${t.name} reviewed.">Review</button></td></tr>`).join('')}</table></div></div><div class="panel"><h3>Lead queue</h3>${leadQueueTable()}</div>`);
}

