function smartTeacherSection(){
  const modes = [
    ['Student Tutor','Practice vocabulary, legal emails, roleplays, pronunciation notes, and homework drafts.','Create a 10-minute practice plan for a B2 lawyer improving client update emails.'],
    ['Speaking Coach','Mock client calls, negotiation phrases, meeting participation, and confidence drills.','Start a client-call roleplay about a delayed contract review.'],
    ['Homework Tutor','Explain instructions, create practice drills, and help improve language before teacher review.','Help me revise homework without giving legal advice.'],
    ['Exam Coach','Prepare for placement checks, progress checks, and completion assessments.','Create a progress-check drill for contract vocabulary and speaking clarity.'],
    ['Teacher Assistant','Draft lesson plans, homework, rubrics, and feedback summaries.','Create a lesson plan for LL.M. legal writing students.'],
    ['Employer Report Helper','Summarize attendance, skill movement, risk flags, and renewal recommendations.','Draft a privacy-safe employer progress summary.'],
    ['Marketing Assistant','Create teacher posts and outreach that follow brand and pricing guardrails.','Write a LinkedIn post for a Legal English teacher without quoting prices.'],
    ['Staff Assistant','Turn queues into daily action lists for leads, campaigns, reports, payouts, and renewals.','Create a staff triage plan for today.']
  ];
  return `<section class="section alt" id="smartteacher">
    <div class="container section-head"><div><div class="eyebrow">SmartTeacher AI</div><h2>AI tutors and assistants for every role — with human oversight.</h2></div><p>SmartTeacher AI improves practice and operations between lessons. It helps with Legal English learning, teacher preparation, employer reporting, marketing copy, and staff triage while staying outside legal advice.</p></div>
    <div class="container grid cols-2"><article class="panel"><div class="ai-mode-grid v17-ai-grid">${modes.map(m=>`<button class="ai-mode js-ai-prompt" data-prompt="${m[2]}"><strong>${m[0]}</strong><span>${m[1]}</span></button>`).join('')}</div></article><article class="panel" id="ai-box">${aiAssistantBox()}</article></div>
    <div class="container clean-note v18-boundary"><strong>AI boundary:</strong> SmartTeacher AI may explain Legal English vocabulary, improve clarity and tone, create language exercises, and support reports. It should not decide legal rights, strategy, enforceability, filing correctness, or professional legal advice.</div>
  </section>`;
}

