function adminDashboard(){
  const gross = employers.reduce((a,e)=>a+e.monthlySpend,0)+95+495+895+29*18+49*8;
  const teacherPayout = Math.round(gross*.47);
  const margin = gross-teacherPayout;
  const dueReviews = state.assignments.filter(a=>a.status==='Submitted' || a.status==='Needs Revision').length;
  return dashLayout('Owner/Admin', `<div class="panel today-panel"><div class="panel-head"><div><h3>Owner/staff command center</h3><p class="muted">What needs action, what money is affected, and what must happen next.</p></div><button class="btn gold js-toast" data-toast="Admin brief exported.">Export brief</button></div><div class="stat-grid"><div class="stat"><strong>$${gross.toLocaleString()}</strong><span>Tracked gross</span></div><div class="stat"><strong>$${teacherPayout.toLocaleString()}</strong><span>Est. payouts</span></div><div class="stat"><strong>$${margin.toLocaleString()}</strong><span>Est. margin</span></div><div class="stat"><strong>${dueReviews}</strong><span>Reviews due</span></div></div></div><div class="panel"><h3>One next best action</h3><div class="next-best"><strong>Clear the revenue-impacting blockers first.</strong><span>Start with firm proposal, teacher campaign approvals, homework reviews, missing closeouts, employer report, and payout holds.</span><a class="btn teal" href="#operations">Open operations</a></div></div><div class="panel"><h3>Today’s blocker board</h3><div class="table-wrap"><table class="table"><tr><th>Lane</th><th>Owner</th><th>Action</th><th>Risk</th></tr>${v18OpsLanes.map(o=>`<tr><td>${o.lane}</td><td>${o.owner}</td><td>${o.today}</td><td>${o.risk}</td></tr>`).join('')}</table></div></div><div class="panel"><h3>Lead queue</h3>${leadQueueTable()}</div>`);
}

