function adminDashboard(){
  const gross = employers.reduce((a,e)=>a+e.monthlySpend,0)+95+495+895+29*18+49*8;
  const teacherPayout = Math.round(gross*.47);
  const margin = gross-teacherPayout;
  const dueReviews = state.assignments.filter(a=>a.status==='Submitted' || a.status==='Needs Revision').length;
  return dashLayout('Owner/Admin', `<div class="panel today-panel"><div class="panel-head"><div><h3>Owner/staff command center</h3><p class="muted">Focus on the few actions that move money, learning progress, reports, renewals, and trust.</p></div><button class="btn gold js-toast" data-toast="Daily operating brief exported.">Export brief</button></div><div class="stat-grid"><div class="stat"><strong>$${gross.toLocaleString()}</strong><span>Tracked gross</span></div><div class="stat"><strong>$${teacherPayout.toLocaleString()}</strong><span>Est. payouts</span></div><div class="stat"><strong>$${margin.toLocaleString()}</strong><span>Est. margin</span></div><div class="stat"><strong>${dueReviews}</strong><span>Reviews due</span></div></div></div><div class="panel"><h3>One next best action</h3><div class="next-best"><strong>Clear the six staff queues in priority order.</strong><span>Money today, teacher growth, classroom closeout, saved work, employer proof, then AI boundary review.</span><a class="btn teal" href="#operations">Open staff queues</a></div></div><div class="panel"><h3>Staff queues</h3><div class="grid cols-3 v19-queue-grid">${v19StaffQueues.map(q=>`<article class="queue-card"><div class="kicker">${q.queue}</div><strong>${q.count}</strong><h3>${q.action}</h3></article>`).join('')}</div></div><div class="panel"><h3>Lead queue</h3>${leadQueueTable()}</div>`);
}

