function renderClassroomPage(){ pageShell(`${hero()}${v19ActionStrip()}${schedulingSection()}${calendarOperationsSection()}${learningTracksSection()}${classroomsSection()}${savedWorkSection()}${homeworkSection()}${examsSection()}${reportsSection()}${smartTeacherSection()}${dashboardsPreview()}`); }

function bindCommon(){
  $$('.js-toast').forEach(btn=>btn.addEventListener('click',()=>toast(btn.dataset.toast || 'Saved.')));
  $$('.js-join-class').forEach(btn=>btn.addEventListener('click',()=>{ const id=btn.dataset.session || 'class'; toast(`${id}: classroom opened. In production this opens the EnglishLegalese room with Google Meet/Zoom attached.`); document.getElementById('classrooms')?.scrollIntoView({behavior:'smooth'}); }));
  $$('.js-role').forEach(btn=>btn.addEventListener('click',()=>{state.role=btn.dataset.role; save(); renderDashboards();}));
  $$('.js-classroom').forEach(btn=>btn.addEventListener('click',()=>{state.classroom=btn.dataset.classroom; save(); const mount=$('#classrooms'); if(mount){ mount.outerHTML=classroomsSection(); bindCommon(); document.getElementById('classrooms')?.scrollIntoView({behavior:'smooth'}); }}));
  $$('.js-form').forEach(form=>form.addEventListener('submit',e=>{ e.preventDefault(); const area=form.closest('article')?.id || ''; if(['student-intake','firm-intake','teacher-apply'].includes(area)) captureLead(form); toast(form.dataset.success || 'Saved.'); form.reset(); }));
  $$('.js-scroll-homework').forEach(btn=>btn.addEventListener('click',()=>document.getElementById('homework')?.scrollIntoView({behavior:'smooth'})));
  $$('.js-scroll-report').forEach(btn=>btn.addEventListener('click',()=>{toast('Report draft generated.'); document.getElementById('reports')?.scrollIntoView({behavior:'smooth'});}));
  $$('.js-complete').forEach(btn=>btn.addEventListener('click',()=>{ const item=state.assignments.find(a=>a.id===btn.dataset.id); if(item){ item.status='Completed'; item.score=item.score || 90; save(); toast('Assignment marked complete. Progress reports updated.'); const list=$('#assignmentList'); if(list) list.innerHTML=assignmentList(); renderDashboards(); } }));
  const assignmentForm=$('#assignmentForm');
  if(assignmentForm){ assignmentForm.addEventListener('submit', e=>{ e.preventDefault(); const newItem={id:'a'+Date.now(), student:$('#hwStudent').value, employer: $('#hwStudent').value.includes('Cohort')?'GlobalLex Partners':'Individual', title:$('#hwTitle').value || 'Legal English assignment', track:$('#hwTrack').value, due:$('#hwDue').value || 'Next lesson', status:'Assigned', score:null, teacher:$('#hwTeacher').value, instructions:$('#hwInstructions').value || 'Complete the assignment and prepare to discuss it in the next lesson.'}; state.assignments.unshift(newItem); save(); $('#assignmentList').innerHTML=assignmentList(); assignmentForm.reset(); toast('Homework assigned. Student, teacher, employer, and admin reports updated.'); }); }
  const seed=$('#seedHomework');
  if(seed){ seed.addEventListener('click',()=>{ const sample={id:'a'+Date.now(), student:'GlobalLex Cohort A', employer:'GlobalLex Partners', title:'Group client-update writing drill', track:'Client calls', due:'July 20', status:'Assigned', score:null, teacher:'Maya Chen, JD', instructions:'Each employee writes a concise client update about a delayed contract review. Teacher reviews clarity, tone, and risk language.'}; state.assignments.unshift(sample); save(); $('#assignmentList').innerHTML=assignmentList(); bindCommon(); toast('Sample group homework added.'); }); }
  const reset=$('#resetHomework');
  if(reset){ reset.addEventListener('click',()=>{ state.assignments=[...baseAssignments]; save(); $('#assignmentList').innerHTML=assignmentList(); bindCommon(); toast('Demo assignments reset.'); }); }
  const send=$('#aiSend');
  if(send){ send.addEventListener('click', sendAi); const inp=$('#aiInput'); if(inp){ inp.addEventListener('keydown', e=>{ if(e.key==='Enter') sendAi(); }); } }
  $$('.js-ai-prompt').forEach(btn=>btn.addEventListener('click',()=>{ const input=$('#aiInput'); if(input){ input.value=btn.dataset.prompt; sendAi(); } }));
}


