function smartTeacherAnswer(q){
  const lower=q.toLowerCase();
  if(lower.includes('schedule') || lower.includes('calendar') || lower.includes('meeting') || lower.includes('class time') || lower.includes('timezone')) return 'Scheduling assistant: treat the EnglishLegalese class session as the source of truth. Confirm package/credits, teacher availability, time zone, calendar invite, video provider, join link, saved work, homework due, and closeout owner before calling the class confirmed.';
  if(lower.includes('record') || lower.includes('privacy') || lower.includes('employer')) return 'Privacy-safe guidance: employer reports should show attendance, homework completion, skill movement, recommendations, and credit usage. Do not expose private drafts, exam answers, or sensitive notes unless authorized by policy and the student.';
  if(lower.includes('email')) return 'Language practice: use a clear subject, one-sentence context, concise status, next step, and polite close. Avoid legal advice. Try rewriting the email in 120 words, then I can help improve tone and clarity.';
  if(lower.includes('contract') || lower.includes('clause')) return 'Contract Legal English drill: practice obligation, discretion, condition, representation, warranty, indemnity, limitation, and termination. Write one plain-English sentence and one formal sentence for each term.';
  if(lower.includes('roleplay') || lower.includes('client')) return 'Client-call roleplay: I will act as a client asking for a status update. Your goal is to explain delay, next step, and expected timeline clearly, without overpromising. Start with: “Thank you for your patience…”';
  if(lower.includes('marketing') || lower.includes('linkedin') || lower.includes('referral') || lower.includes('campaign')) return 'Teacher marketing assistant: name one specific Legal English outcome, use your approved EnglishLegalese link, invite the reader to the diagnostic, and never quote private/off-platform prices. CTA: “Take the Legal English diagnostic and request my class through EnglishLegalese.”';
  if(lower.includes('report') || lower.includes('progress')) return 'Report assistant: summarize attendance, homework completion, skill movement, teacher observation, next recommendation, credit usage, and renewal risk. Keep employer reports privacy-safe.';
  if(lower.includes('lesson plan') || lower.includes('teacher')) return 'Teacher assistant plan: 5-minute warm-up, 15-minute language focus, 15-minute legal communication task, 10-minute roleplay, and 5-minute homework briefing. Score clarity, accuracy, tone, and confidence.';
  if(lower.includes('homework') || lower.includes('assignment')) return 'Homework tutor: create one short writing task, one vocabulary set, one speaking prompt, and one teacher-reviewed deliverable. AI helps practice; teacher feedback is the official review.';
  return 'SmartTeacher AI suggestion: turn this into a Legal English practice task with vocabulary, a short writing exercise, a speaking roleplay, and one teacher-reviewed homework deliverable. This is language training only, not legal advice.';
}

