  const e=employers[0];
  return dashLayout('Employer', `<div class="panel today-panel"><div class="panel-head"><div><h3>${e.name}: training progress</h3><p class="muted">${e.plan} · ${e.employees} employees · privacy-safe reporting</p></div><a class="btn gold" href="#reports">View report</a></div><div class="stat-grid"><div class="stat"><strong>${e.creditBalance}</strong><span>Credits left</span></div><div class="stat"><strong>${e.progress}%</strong><span>Team progress</span></div><div class="stat"><strong>88%</strong><span>Attendance</span></div><div class="stat"><strong>${e.reportDue}</strong><span>Report due</span></div></div></div><div class="panel"><h3>One next best action</h3><div class="next-best"><strong>Confirm the roster before the next group class.</strong><span>This prevents calendar, video, attendance, and report issues.</span><a class="btn teal" href="#scheduling">Open schedule</a></div></div><div class="panel"><h3>What employers see</h3><p class="muted">Attendance, homework completion, skill movement, assessment status, credit usage, recommendations, and renewal options. Private drafts and exam answers stay restricted unless authorized.</p></div>`);
