function adminDashboard(){
  const gross = employers.reduce((a,e)=>a+e.monthlySpend,0)+95+495+895+29*18+49*8;
  const teacherPayout = Math.round(gross*.47);
  const margin = gross-teacherPayout;
  return dashLayout('Owner/Admin', `<div class="panel today-panel"><div class="panel-head"><div><h3>Owner/staff command center</h3><p class="muted">Revenue, class readiness, teacher growth, reports, credits, payouts, renewals, and AI boundaries.</p></div><button class="btn gold js-toast" data-toast="Unified daily brief exported.">Export brief</button></div><div class="stat-grid"><div class="stat"><strong>$${gross.toLocaleString()}</strong><span>Tracked gross</span></div><div class="stat"><strong>$${teacherPayout.toLocaleString()}</strong><span>Est. payouts</span></div><div class="stat"><strong>$${margin.toLocaleString()}</strong><span>Est. margin</span></div><div class="stat"><strong>6</strong><span>Blockers</span></div></div></div><div class="panel"><h3>One next best action</h3><div class="next-best"><strong>Clear schedule/video/roster blockers before confirming classes.</strong><span>Class readiness protects trust, reports, teacher payouts, and employer renewals.</span><a class="btn teal" href="#calendar-ops">Open exception queue</a></div></div><div class="panel"><h3>Unified session map</h3><div class="table-wrap"><table class="table"><tr><th>Record</th><th>Schedule</th><th>Classroom</th><th>Proof</th><th>Money</th><th>Next</th></tr>${v112SessionMap.map(s=>`<tr><td>${s.record}</td><td>${s.schedule}</td><td>${s.classroom}</td><td>${s.proof}</td><td>${s.money}</td><td>${s.next}</td></tr>`).join('')}</table></div></div>`);
}

function operationsSection(){
  return `<section class="section" id="operations"><div class="container section-head"><div><div class="eyebrow">Owner + staff operations</div><h2>Operate by blockers that affect trust or revenue.</h2></div><p>The staff view should make the next business action obvious: sell, schedule, teach, close out, report, pay, renew, or pause.</p></div><div class="container v112-ops-board"><article class="panel"><h3>Risk queue</h3><div class="v112-risk-list">${v112OpsRisks.map(r=>`<div><strong>${r[0]}</strong><span>Needs operating rule</span><p>${r[1]}</p></div>`).join('')}</div></article><article class="panel"><h3>Daily staff sequence</h3><div class="ops-checklist"><label><input type="checkbox" checked> Review new student / employer / teacher leads</label><label><input type="checkbox" checked> Verify package, invoice, or credit status</label><label><input type="checkbox"> Clear calendar, video, roster, and time-zone blockers</label><label><input type="checkbox"> Confirm teacher match and class readiness</label><label><input type="checkbox"> Review homework, saved work, and exam blockers</label><label><input type="checkbox"> Generate progress reports after closeout</label><label><input type="checkbox"> Approve teacher payouts after quality check</label><label><input type="checkbox"> Trigger renewal, top-up, or next package offer</label><label><input type="checkbox"> Review teacher marketing claims and attribution</label><label><input type="checkbox"> Check SmartTeacher AI boundary flags</label></div></article></div></section>`;
}

