function smartTeacherAnswer(q){
  const lower=q.toLowerCase();
  if(lower.includes('schedule') || lower.includes('calendar') || lower.includes('video') || lower.includes('zoom') || lower.includes('meet')) return 'Scheduling assistant: confirm package/credit status, teacher availability, learner time zone, calendar invite, Google Meet or Zoom room, saved work, homework/exam context, and recording consent before marking the class ready.';
  if(lower.includes('class record') || lower.includes('session') || lower.includes('closeout')) return 'Class-session assistant: one EnglishLegalese record should connect buyer, teacher, learner/cohort, calendar invite, video room, saved work, class notes, homework, assessment, report, credit deduction, payout status, and renewal prompt.';
  if(lower.includes('email')) return 'Language practice: use a clear subject, one-sentence context, concise status, next step, and a polite close. Avoid giving legal advice. Try rewriting the email in 120 words, then I can help improve tone and clarity.';
  if(lower.includes('contract') || lower.includes('clause')) return 'Contract Legal English drill: define obligation, discretion, condition, representation, warranty, indemnity, and termination. Then write one plain-English sentence and one formal sentence for each term.';
  if(lower.includes('roleplay') || lower.includes('client')) return 'Client-call roleplay: I will act as a client asking for a status update. Your goal is to explain delay, next step, and expected timeline clearly, without overpromising. Start with: “Thank you for your patience…”';
  if(lower.includes('marketing') || lower.includes('linkedin') || lower.includes('referral') || lower.includes('campaign')) return 'Teacher marketing assistant: name one specific Legal English outcome, use only an approved profile/class link, invite the reader to the free diagnostic, avoid quoting private prices, and keep all checkout inside EnglishLegalese.';
  if(lower.includes('report') || lower.includes('progress')) return 'Report assistant: summarize attendance, homework completion, skill movement, teacher observation, next recommendation, and renewal risk. Employer reports should be privacy-safe and should not expose private drafts or exam answers unless authorized.';
  if(lower.includes('lesson plan') || lower.includes('teacher')) return 'Teacher assistant plan: begin with a 5-minute warm-up, 15-minute language focus, 15-minute legal communication task, 10-minute roleplay, and 5-minute homework briefing. Score clarity, accuracy, tone, and confidence.';
  if(lower.includes('homework') || lower.includes('assignment') || lower.includes('exam')) return 'Homework/exam tutor: create one short writing task, one vocabulary set, one speaking prompt, and one check-for-understanding assessment. Save progress so the teacher can review the work in the next class.';
  return 'SmartTeacher AI suggestion: turn this into a Legal English practice task with vocabulary, a short writing exercise, a speaking roleplay, and one teacher-reviewed homework deliverable. This is language training only, not legal advice.';
}

