function smartTeacherAnswer(q){
  const lower = q.toLowerCase();
  if(lower.includes('credential') || lower.includes('infrastructure') || lower.includes('activate') || lower.includes('live users')) return 'Production activation assistant: the code is ready to connect live services, but the actual credentials must be created in the owner accounts and stored as environment variables. Required gates are PostgreSQL, auth secret, Stripe and webhooks, object storage, SMTP email, Google Meet, server-side AI, backup checkpoint, and post-deploy smoke tests. Do not onboard real paid classroom users while the app is still using local JSON fallback.';
  if(lower.includes('owner account') || lower.includes('admin account')) return 'Owner bootstrap assistant: set OWNER_EMAIL, OWNER_PASSWORD, and OWNER_NAME in the production environment, run npm run owner:create once, log in, rotate the password, and then remove the temporary OWNER_PASSWORD from environment variables.';
  if(lower.includes('backup') || lower.includes('restore')) return 'Backup assistant: production must use managed PostgreSQL backups plus recorded backup checkpoints. Before risky migrations, take a manual backup and verify that restore instructions exist. Code deployments should never reset the database or object storage.';
  return v121PreviousSmartTeacherAnswer(q);
}

