const v124PreviousSmartTeacherAnswer = smartTeacherAnswer;
function smartTeacherAnswer(q){
  const lower = q.toLowerCase();
  if(lower.includes('why') && (lower.includes('ai') || lower.includes('translate'))) return 'AI translation is useful, but Legal English performance requires more than translated words: context, judgment, professional tone, confidentiality awareness, speaking confidence, and the ability to review AI output safely. EnglishLegalese helps you practice with AI and improve with teachers.';
  if(lower.includes('translation risk') || lower.includes('risky translation') || lower.includes('ai translated')) return 'AI Translator Safety exercise: compare the AI output to the intended legal/business meaning. Look for special legal terms, deadlines, obligations, defined terms, tone problems, missing context, and privacy concerns. Save the issue and bring it to your teacher for language review.';
  if(lower.includes('confidential') || lower.includes('privileged') || lower.includes('client information')) return 'Confidentiality check: do not paste confidential, privileged, client-identifying, sensitive, or high-stakes documents into AI tools unless you have authority and the platform privacy/security terms clearly allow it. Use fictional, anonymized, or cleared text for practice.';
  if(lower.includes('teacher review') || lower.includes('bring this to my teacher')) return 'Teacher review workflow: save the AI practice to your lesson folder, add what feels uncertain, mark whether the concern is tone, meaning, vocabulary, confidence, or confidentiality, and ask your teacher to review it in the next live class.';
  if(lower.includes('employer') && (lower.includes('report') || lower.includes('privacy'))) return 'Employer-safe report guidance: show attendance, completion, skill progress, AI translator safety practice, professional tone, and recommended next training. Do not expose private drafts, sensitive uploads, or private AI practice text unless permissions clearly allow it.';
  if(lower.includes('marketing') || lower.includes('linkedin') || lower.includes('teacher post')) return 'AI-era teacher marketing copy: “AI can translate words, but professionals still need judgment, tone, context, speaking confidence, and the ability to review AI output safely. I teach Legal English for real work through EnglishLegalese.” Use an approved tracking link and keep pricing/checkout on-platform.';
  return v124PreviousSmartTeacherAnswer(q);
}

