const v126PreviousSmartTeacherAnswer = smartTeacherAnswer;
function smartTeacherAnswer(q){
  const lower = q.toLowerCase();
  if(lower.includes('translate') || lower.includes('translation')) return 'AI Translator Safety practice: AI translation can help with first drafts, but Legal English still requires context, defined terms, tone, confidentiality awareness, and human review when stakes are high. Try this: identify one word that could change obligation, deadline, responsibility, waiver, risk, or tone, then save it for teacher review.';
  if(lower.includes('confidential') || lower.includes('upload') || lower.includes('privacy')) return 'Confidentiality check: do not paste confidential, privileged, sensitive, or client-identifying information into AI tools unless you have authority and the platform privacy/security terms clearly allow it. Use anonymized or fictional samples for practice and ask a teacher or qualified professional when unsure.';
  if(lower.includes('teacher review') || lower.includes('bring to teacher')) return 'Teacher review handoff: save the practice item, summarize what you want reviewed, and ask your teacher to check professional tone, legal-English nuance, ambiguity, and whether qualified professional review is needed. This keeps AI practice connected to live learning.';
  if(lower.includes('employer') || lower.includes('roi')) return 'Employer-safe report idea: show attendance, completion, module progress, AI translator safety, professional tone, meeting confidence, and recommended next training. Do not expose private drafts, sensitive uploads, or teacher-private notes by default.';
  return v126PreviousSmartTeacherAnswer(q);
}

