const v127PreviousSmartTeacherAnswer = smartTeacherAnswer;
function smartTeacherAnswer(q){
  const lower = q.toLowerCase();
  if(lower.includes('why') && (lower.includes('ai') || lower.includes('translator') || lower.includes('translate'))) return 'Because legal work is more than translation. AI can help convert words, but Legal English performance still requires judgment, context, professional tone, confidentiality awareness, speaking confidence, document fluency, and the ability to review AI output safely. Practice with AI, improve with teachers, and use qualified review when stakes are high.';
  if(lower.includes('class') || lower.includes('calendar') || lower.includes('meet') || lower.includes('zoom')) return 'Classroom flow: confirm credits, teacher match, time zone, calendar invite, Google Meet or Zoom link, privacy status, saved work, homework, attendance, closeout, report status, credit deduction, and payout dependency. Recording should stay off unless everyone clearly consents.';
  if(lower.includes('teacher marketing') || lower.includes('linkedin') || lower.includes('social') || lower.includes('campaign')) return 'Teacher marketing assistant: use approved EnglishLegalese copy and tracking links. Do not publish private teacher prices, legal-advice claims, guaranteed outcomes, or off-platform payment instructions. Explain that AI can translate words, but professionals still need Legal English judgment, tone, confidence, and safe review.';
  if(lower.includes('employer report') || lower.includes('privacy-safe')) return 'Employer-safe report: show attendance, completion, module progress, AI translator safety, professional tone, meeting confidence, document fluency, recommended next training, and renewal/top-up suggestions. Do not expose private drafts, sensitive uploads, or teacher-private notes by default.';
  return v127PreviousSmartTeacherAnswer(q);
}

