    state.employerSafeReports = state.employerSafeReports || [];
    state.employerSafeReports.unshift({
      id:'er-lang-'+Date.now(), employer:'GlobalLex Partners', period:'Language-support training snapshot', learners:'Active learners using support only when stuck', attendance:'High-level only', homework:'High-level only', aiSafety:'Translation Bridge used as learning support', tone:'Professional tone practice protected', confidence:'Learners return to speaking/writing in Legal English', privacy:`Employer-safe only. Languages requested (${languages}) may be summarized at a high level, but raw native-language explanations, private drafts, sensitive uploads, and teacher-private notes are excluded by default.`, next:'Continue AI Translator Safety Lab and teacher-led speaking/writing practice.', createdAt:v141Today()
    });
