  function bindV141Actions(root=document){
    $$('.js-v141-language-select', root).forEach(sel => {
      if(sel.dataset.v141Bound) return;
      sel.dataset.v141Bound = '1';
      sel.addEventListener('change', () => { state.v141SelectedLanguage = sel.value; save(); });
    });
    $$('.js-v141-request-language', root).forEach(btn => {
      if(btn.dataset.v141Bound) return;
      btn.dataset.v141Bound = '1';
      btn.addEventListener('click', () => {
        const visibleSelect = document.querySelector('.js-v141-language-select');
        if(visibleSelect) state.v141SelectedLanguage = visibleSelect.value;
        v141CreateLanguageRequest();
        toast('Language-help request saved to the lesson folder and connected to teacher review when needed.');
        v141Refresh();
      });
    });
    $$('.js-v141-language-summary', root).forEach(btn => {
      if(btn.dataset.v141Bound) return;
      btn.dataset.v141Bound = '1';
      btn.addEventListener('click', () => {
        v141GenerateEmployerLanguageSummary();
        toast('Employer-safe language-support summary generated without exposing private native-language text.');
        v141Refresh();
      });
    });
    $$('.js-v141-teacher-route', root).forEach(btn => {
      if(btn.dataset.v141Bound) return;
      btn.dataset.v141Bound = '1';
      btn.addEventListener('click', () => {
        const r = (state.v141LanguageRequests || [])[Number(btn.dataset.index)] || (state.v141LanguageRequests || [])[0] || v141CreateLanguageRequest();
        state.teacherReviewHandoffs = state.teacherReviewHandoffs || [];
        state.teacherReviewHandoffs.unshift({ id:'tr-lang-'+Date.now(), student:r.learner, teacher:'Maya Chen, JD', title:`Teacher review: ${r.language} language bridge`, reason:'Check that the explanation returns the learner to Legal English and does not create false confidence or legal/translation boundaries.', status:'Teacher review needed', source:'v1.41 Language Bridge', createdAt:v141Today() });
        toast('Language-help item routed to teacher review.');
        v141Refresh();
      });
    });
  }

  const v141PreviousBindCommon = bindCommon;
  bindCommon = function(){ v141PreviousBindCommon(); bindV141Actions(document); };


  /* v1.42.0 Continuity Command Center: make learning proof, classroom action, teacher marketing, and no-data-loss operations feel connected instead of scattered */
  const v142VersionLabel = 'v1.42.0 Continuity Command Center';
  brand.version = v142VersionLabel;

  const v142ProtectedRecords = [
    'Student accounts and profiles',
    'Teacher accounts, notes, closeouts, and payout status',
    'Employer accounts, cohorts, reports, renewals, and credit ledgers',
    'Class sessions, internal calendars, time zones, reminders, video/provider links, and manual regional links',
    'Saved SmartTeacher AI practice, lesson-folder items, homework, classwork, exams, test scores, progress reports, and certificates',
    'Translation Bridge and major-language support records',
    'Teacher-review handoffs, confidentiality checks, support threads, uploaded file metadata, audit logs, and staff action queues',
    'Stripe/payment status, packages, credits, invoices, refunds, and teacher payout review records'
  ];

  const v142FlowSteps = [
    {title:'1. Save the work', text:'SmartTeacher AI practice, Translation Bridge help, homework, or classroom notes are saved to the learner folder with privacy labels.'},
    {title:'2. Route review', text:'Important language, AI-translation risk, native-language support, or confidentiality concerns become teacher/staff review handoffs.'},
    {title:'3. Teach live', text:'Teacher uses a simple classroom command panel: learner card, agenda, correction pad, roleplay, Translation Bridge, homework, closeout.'},
    {title:'4. Prove progress', text:'Teacher-reviewed progress becomes homework, reports, certificates, and employer-safe summaries without exposing private drafts.'},
    {title:'5. Preserve data', text:'Deployments update code only. Persistent records, payment status, calendars, reports, test scores, and class history are not wiped.'}
  ];

  function v142ReadJson(key, fallback) {
    try {
      const raw = localStorage.getItem(key);
      if (!raw) return fallback;
      const parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : fallback;
    } catch (_) { return fallback; }
  }

  const v142BaseContinuityActions = [
    {id:'cc1', owner:'Ana Kowalska', role:'student', type:'Lesson folder', action:'Saved SmartTeacher rewrite practice to teacher-visible folder', status:'Ready for teacher review', privacy:'Student + teacher only', next:'Teacher marks reviewed or assigns homework'},
    {id:'cc2', owner:'Maya Chen, JD', role:'teacher', type:'Live classroom', action:'Use Translation Bridge flag in side-by-side correction pad', status:'Classroom-ready', privacy:'Do not expose native-language text to employer', next:'Close out class and create employer-safe summary'},
    {id:'cc3', owner:'GlobalLex Partners', role:'employer', type:'Employer report', action:'Generate high-level progress report', status:'Privacy-safe draft', privacy:'No private drafts, raw AI, raw native-language text, or teacher-private notes', next:'Staff/teacher review before release'},
    {id:'cc4', owner:'Owner/Admin', role:'staff', type:'Deployment guardrail', action:'Confirm v1.42 code deploy preserves production data stores', status:'Required before deploy', privacy:'No live secrets in ZIP', next:'Run checks, smoke test, and never reset production data'}
  ];

  const v142BaseMarketingApprovals = [
    {id:'ma1', teacher:'Maya Chen, JD', channel:'LinkedIn', asset:'AI-era Legal English post', status:'Approved copy only', rule:'No legal advice, no certified translation, no off-platform pricing', next:'Use tracked link/QR'},
    {id:'ma2', teacher:'James Whitaker', channel:'Webinar', asset:'Contracts and AI Translator Safety invite', status:'Staff review needed', rule:'Avoid unsupported university comparison claims', next:'Staff claim review'}
  ];

  state.v142ContinuityActions = v142ReadJson('elV142ContinuityActions', v142BaseContinuityActions);
  state.v142MarketingApprovals = v142ReadJson('elV142MarketingApprovals', v142BaseMarketingApprovals);
  state.v142ClassroomMode = localStorage.getItem('elV142ClassroomMode') || 'Before class';

  const v142PreviousSave = save;
  save = function(){
    v142PreviousSave();
    localStorage.setItem('elV142ContinuityActions', JSON.stringify(state.v142ContinuityActions || []));
    localStorage.setItem('elV142MarketingApprovals', JSON.stringify(state.v142MarketingApprovals || []));
    localStorage.setItem('elV142ClassroomMode', state.v142ClassroomMode || 'Before class');
  };

  function v142Today(){ return new Date().toLocaleDateString(undefined, { month:'short', day:'numeric' }); }
  function v142StatusClass(status=''){
    if(/required|review|needed|guardrail/i.test(status)) return 'gold';
    if(/ready|approved|safe|saved|classroom/i.test(status)) return 'green';
    return 'gray';
  }
  function v142ProtectedList(){ return v142ProtectedRecords.map(item => `<li>${escapeHtml(item)}</li>`).join(''); }
  function v142FlowCards(){ return v142FlowSteps.map(step => `<article class="card"><h3>${escapeHtml(step.title)}</h3><p>${escapeHtml(step.text)}</p></article>`).join(''); }

  function v142ContinuityRows(limit=6){
    const rows = (state.v142ContinuityActions || []).slice(0, limit).map((r, idx) => `<tr><td><strong>${escapeHtml(r.owner)}</strong><br><span class="muted">${escapeHtml(r.role)}</span></td><td>${escapeHtml(r.type)}</td><td>${escapeHtml(r.action)}</td><td><span class="status ${v142StatusClass(r.status)}">${escapeHtml(r.status)}</span></td><td>${escapeHtml(r.privacy)}</td><td>${escapeHtml(r.next)}</td><td><button class="btn light small js-v142-route-review" data-index="${idx}">Route</button></td></tr>`).join('');
    return `<div class="table-wrap"><table class="table v142-table"><tr><th>Owner</th><th>Record</th><th>Action</th><th>Status</th><th>Privacy</th><th>Next</th><th></th></tr>${rows || '<tr><td colspan="7">No continuity actions yet.</td></tr>'}</table></div>`;
  }

  function v142MarketingRows(limit=4){
    const rows = (state.v142MarketingApprovals || []).slice(0, limit).map((m, idx) => `<tr><td><strong>${escapeHtml(m.teacher)}</strong></td><td>${escapeHtml(m.channel)}</td><td>${escapeHtml(m.asset)}</td><td><span class="status ${v142StatusClass(m.status)}">${escapeHtml(m.status)}</span></td><td>${escapeHtml(m.rule)}</td><td>${escapeHtml(m.next)}</td><td><button class="btn light small js-v142-approve-marketing" data-index="${idx}">Approve path</button></td></tr>`).join('');
    return `<div class="table-wrap"><table class="table v142-table"><tr><th>Teacher</th><th>Channel</th><th>Asset</th><th>Status</th><th>Guardrail</th><th>Next</th><th></th></tr>${rows || '<tr><td colspan="7">No marketing approval items yet.</td></tr>'}</table></div>`;
  }

  function v142CreateContinuityAction(opts={}){
    const action = {
      id:'cc'+Date.now(),
      owner: opts.owner || (state.role === 'teacher' ? 'Maya Chen, JD' : state.role === 'employer' ? 'GlobalLex Partners' : state.role === 'admin' ? 'Owner/Admin' : 'Ana Kowalska'),
      role: opts.role || state.role || 'student',
      type: opts.type || 'SmartTeacher proof loop',
      action: opts.action || 'Save practice to lesson folder, route teacher review, and keep employer report privacy-safe.',
      status: opts.status || 'Ready for teacher review',
      privacy: opts.privacy || 'Student + teacher only until employer-safe summary is generated',
      next: opts.next || 'Teacher review, homework, closeout, or employer-safe report',
      createdAt: v142Today()
    };
    state.v142ContinuityActions.unshift(action);
    state.lessonFolderItems = state.lessonFolderItems || [];
    state.lessonFolderItems.unshift({ id:'lf-v142-'+Date.now(), student:action.owner, title:action.action, source:'v1.42 Continuity Command Center', status:'Saved to lesson folder', visibility:action.privacy, next:action.next, createdAt:v142Today() });
    if(/teacher|review|risk|translation|ai|confidential|native/i.test(action.action + ' ' + action.status + ' ' + action.next)) {
      state.teacherReviewHandoffs = state.teacherReviewHandoffs || [];
      state.teacherReviewHandoffs.unshift({ id:'tr-v142-'+Date.now(), student:action.owner, teacher:'Assigned teacher', title:`Review: ${action.type}`, reason:'v1.42 routed this item because AI-era Legal English, Translation Bridge, confidentiality, or professional tone may need teacher judgment.', status:'Teacher review needed', source:'v1.42 Continuity Command Center', createdAt:v142Today() });
    }
    return action;
  }

  function v142CreateEmployerSafeReport(){
    state.employerSafeReports = state.employerSafeReports || [];
    state.employerSafeReports.unshift({
      id:'er-v142-'+Date.now(), employer:'GlobalLex Partners', period:'Continuity proof snapshot', learners:'Active learners with saved practice/review history', attendance:'High-level only', homework:'Teacher-reviewed status only', aiSafety:'AI Translator Safety and SmartTeacher practice summarized without raw prompts', tone:'Professional tone progress summarized', confidence:'Speaking/writing confidence summarized', privacy:'Employer-safe only: excludes private drafts, raw AI practice, raw native-language explanations, sensitive uploads, teacher-private notes, and confidential content by default.', next:'Continue teacher-led Legal English practice, AI Translator Safety Lab, and targeted speaking/writing modules.', createdAt:v142Today()
    });
    return state.employerSafeReports[0];
  }

