  const v142PreviousSmartTeacherAnswer = smartTeacherAnswer;
  smartTeacherAnswer = function(q=''){
    const lower = q.toLowerCase();
    if(lower.includes('continuity') || lower.includes('lose') || lower.includes('preserve') || lower.includes('progress') || lower.includes('test score') || lower.includes('payment') || lower.includes('calendar')) return 'v1.42 continuity rule: EnglishLegalese practice, lesson folders, Translation Bridge records, teacher reviews, homework, reports, certificates, test scores, calendar/class links, payments, credits, employer records, and audit history must live in persistent storage and survive code deployments. Code updates should never wipe production data.';
    if(lower.includes('teacher command') || lower.includes('online classroom') || lower.includes('live class')) return 'Teacher classroom command should stay simple: before class, review the learner card, goals, saved AI practice, language flags, time zone, and class link; during class, use agenda, correction pad, roleplay, Translation Bridge, and AI translation-risk lens; after class, close out attendance, homework, teacher-review handoffs, employer-safe notes, and payout readiness.';
    if(lower.includes('marketing') || lower.includes('social') || lower.includes('linkedin') || lower.includes('whatsapp')) return 'Teacher marketing should use approved EnglishLegalese copy, tracked links, QR codes, and staff claim review. Do not allow off-platform pricing, unsupported university comparisons, legal-advice claims, certified-translation claims, or claims that AI/translation replaces teachers or professional review.';
    if(lower.includes('employer report') || lower.includes('employer-safe')) return 'Employer-safe reports should show high-level progress, attendance, completion, AI Translator Safety practice, professional tone, speaking confidence, and recommended next training. They should not expose private drafts, raw SmartTeacher prompts, raw native-language explanations, sensitive uploads, or teacher-private notes unless permission is clear.';
    return v142PreviousSmartTeacherAnswer(q);
  };

