  function bindV142Actions(root=document){
    $$('.js-v142-create-action', root).forEach(btn => {
      if(btn.dataset.v142Bound) return;
      btn.dataset.v142Bound = '1';
      btn.addEventListener('click', () => { v142CreateContinuityAction(); save(); toast('Continuity action saved and routed into the proof loop.'); v142Refresh(); });
    });
    $$('.js-v142-route-review', root).forEach(btn => {
      if(btn.dataset.v142Bound) return;
      btn.dataset.v142Bound = '1';
      btn.addEventListener('click', () => {
        const r = (state.v142ContinuityActions || [])[Number(btn.dataset.index)] || v142CreateContinuityAction();
        state.teacherReviewHandoffs = state.teacherReviewHandoffs || [];
        state.teacherReviewHandoffs.unshift({ id:'tr-v142-'+Date.now(), student:r.owner, teacher:'Assigned teacher', title:`Teacher review: ${r.type}`, reason:'Routed from v1.42 continuity queue for Legal English judgment, AI translator safety, Translation Bridge boundary, or privacy review.', status:'Teacher review needed', source:'v1.42 Continuity Command Center', createdAt:v142Today() });
        save(); toast('Routed to teacher review.'); v142Refresh();
      });
    });
    $$('.js-v142-employer-report', root).forEach(btn => {
      if(btn.dataset.v142Bound) return;
      btn.dataset.v142Bound = '1';
      btn.addEventListener('click', () => { v142CreateEmployerSafeReport(); save(); toast('Employer-safe report snapshot generated.'); v142Refresh(); });
    });
    $$('.js-v142-new-marketing', root).forEach(btn => {
      if(btn.dataset.v142Bound) return;
      btn.dataset.v142Bound = '1';
      btn.addEventListener('click', () => { v142CreateMarketingApproval(); save(); toast('Teacher marketing item added for staff review.'); v142Refresh(); });
    });
    $$('.js-v142-approve-marketing', root).forEach(btn => {
      if(btn.dataset.v142Bound) return;
      btn.dataset.v142Bound = '1';
      btn.addEventListener('click', () => {
        const m = (state.v142MarketingApprovals || [])[Number(btn.dataset.index)];
        if(m) { m.status = 'Approved copy path'; m.next = 'Publish with tracked link/QR and platform-controlled pricing.'; }
        save(); toast('Marketing item moved to approved-copy path.'); v142Refresh();
      });
    });
  }

  const v142PreviousBindCommon = bindCommon;
