    $$('.js-v146-employer-brief', root).forEach(btn=>{ if(btn.dataset.v146Bound) return; btn.dataset.v146Bound='1'; btn.addEventListener('click',()=>{ state.employerSafeReports=state.employerSafeReports||[]; state.employerSafeReports.unshift({id:'er-v146-'+Date.now(), employer:'GlobalLex Partners', period:'Live skills progress brief', attendance:'90%', homework:'82%', aiSafety:'AI translator safety practiced while returning to Legal English performance.', tone:'Teacher-reviewed tone and clarity summarized.', confidence:'Speaking/listening progress summarized without raw recordings or transcripts.', privacy:'Employer-safe: excludes recordings, transcripts, private drafts, native-language explanations, uploads, test answers, and teacher-private notes by default.', next:'Continue weakest-skill workshop and teacher-led AI Translator Safety review.', createdAt:new Date().toLocaleDateString()}); save(); toast('Employer-safe skills brief created.'); }); });
