  state.v150LanguageContinuityChecks = state.v150LanguageContinuityChecks || [];

  const v150FeaturedLanguages = ['Spanish','Chinese (Simplified)','Chinese (Traditional)','Arabic','French','Portuguese','Russian','Hindi','Bengali','Urdu','German','Japanese','Korean','Vietnamese','Turkish','Italian','Polish','Ukrainian','Persian/Farsi','Indonesian','Tagalog/Filipino','Swahili','Hebrew','Thai','Dutch','Greek','Romanian','Czech','Hungarian','Malay'];
