  const v150ProtectedRecords = ['student work','lesson folders','homework','voice/spoken practice','listening notes','reading scores','writing drafts','SmartTeacher AI practice','Translation Bridge records','calendars','class links','payments','credits','reports','certificates','test scores','teacher notes','employer records','uploads','support history','audit logs','payouts'];

  function v150LanguageButtons(){ return v150FeaturedLanguages.slice(0,16).map(lang=>`<button class="btn ${state.v150SelectedLanguage===lang?'gold':'light'} small js-v150-language" data-language="${escapeHtml(lang)}">${escapeHtml(lang)}</button>`).join(''); }
  function v150PlanRows(){ return (state.v150LanguagePlans||[]).slice(0,5).map(plan=>`<tr><td><strong>${escapeHtml(plan.language)}</strong><br><span class="muted">${escapeHtml(plan.learner)}</span></td><td>${escapeHtml(plan.nextStep)}</td><td>${escapeHtml(plan.enables)}</td><td>${escapeHtml(plan.createdAt)}</td></tr>`).join('') || '<tr><td colspan="4" class="muted">No v1.50 language learning bridge plans yet. Choose a language and create one.</td></tr>'; }
  function v150CreateLanguagePlan(language = state.v150SelectedLanguage){
    const plan = { id:'v150-lang-'+Date.now(), learner:'Student / cohort', language, nextStep:`Use Simple English first, explain in ${language} only enough to get unstuck, save to lesson folder, then return to Legal English practice.`, enables:'Platform steps, AI practice, homework, class links, teacher questions, and four-skills practice become easier to understand.', createdAt:new Date().toLocaleDateString() };
    state.v150LanguagePlans.unshift(plan);
    state.savedWork = state.savedWork || [];
    state.savedWork.unshift({ id:'sw-v150-'+Date.now(), title:`100+ Language Bridge plan: ${language}`, type:'language_learning_bridge', status:'Saved for student + teacher review', visibility:'student_teacher_staff_only', preview:plan.nextStep, createdAt:plan.createdAt });
    state.staffTasks = state.staffTasks || [];
    state.staffTasks.unshift({ id:'st-v150-lang-'+Date.now(), title:`v1.50 Language Bridge onboarding: ${language}`, priority:'normal', owner:'staff', status:'Open', next:'Confirm learning support boundaries, preferred language, teacher review path, and no-data-loss protection.', createdAt:plan.createdAt });
    return plan;
  }
  function v150CreateEmployerCard(){
    const card = { id:'v150-employer-'+Date.now(), languageCount:`${v150LanguageCount}+ major languages`, safeSummary:'Employers can see high-level language-support readiness, attendance, completion, skill progress, and next training; private drafts, raw explanations, transcripts, recordings, and teacher-private notes stay excluded by default.', createdAt:new Date().toLocaleDateString() };
    state.v150EmployerLanguageCards.unshift(card);
    return card;
  }
  function v150RunContinuityCheck(){
    const check = { id:'v150-continuity-'+Date.now(), status:'Passed 100+ language bridge preservation screen', protected:v150ProtectedRecords.join(', '), rule:'Language-support improvements must be code-only/additive by default and must not wipe learner work, calendars, payments, reports, certificates, scores, notes, employer records, uploads, audits, or payouts.', createdAt:new Date().toLocaleDateString() };
    state.v150LanguageContinuityChecks.unshift(check);
    return check;
  }
  function v150Section(){
    return `<section class="section v150-section accent" id="v150-language-learning-bridge"><div class="container section-head"><div><div class="eyebrow">v1.50 100+ Language Learning Bridge</div><h2>Get unstuck in 100+ major languages — then return to Legal English.</h2></div><p>Students should know this as soon as they land: EnglishLegalese can explain lessons, AI practice, homework, class links, scheduling, billing, certificates, and support steps in a preferred language when needed, while keeping the goal real Legal English performance.</p></div><div class="container grid cols-2"><article class="panel v150-bridge-hero"><div class="metric-large"><strong>${v150LanguageCount}+</strong><span>major language options for learning support</span></div><p class="clean-note"><strong>Marketing message:</strong> AI can translate words. EnglishLegalese helps learners use language support wisely so they can understand, ask better questions, practice speaking/listening/reading/writing, and build confidence beyond translation.</p><div class="tag-row">${v150LanguageButtons()}</div><div class="tag-row"><button class="btn gold js-v150-create-plan">Create language bridge plan</button><button class="btn teal js-v150-employer-card">Create employer-safe card</button><button class="btn light js-v150-continuity">Run preservation check</button></div></article><article class="panel"><h3>What native-language support enables</h3><ul class="feature-list">${v150Enables.map(item=>`<li>${escapeHtml(item)}</li>`).join('')}</ul><p class="notice"><strong>Boundary:</strong> translation help is a bridge back to Legal English. It is not certified translation, court interpretation, legal advice, or final legal meaning.</p></article></div><div class="container grid cols-3"><article class="card"><h3>Students</h3><p>Choose a preferred language, get Simple English or native-language explanation, save confusing items, ask a teacher, and keep practicing Legal English.</p></article><article class="card"><h3>Teachers</h3><p>Use the learner language card, side-by-side bridge pad, false-friend notes, and review handoffs without turning class into generic translation.</p></article><article class="card"><h3>Employers</h3><p>See privacy-safe readiness and progress. Raw native-language explanations, private drafts, recordings, transcripts, and teacher-private notes stay private by default.</p></article></div><div class="container panel"><div class="panel-head"><div><h3>Recent language bridge plans</h3><p class="muted">These plans make the 100+ language promise operational: support the learner, save work, involve a teacher, and return to Legal English.</p></div><span class="status green">${v150LanguageCount}+ major languages + privacy-safe</span></div><div class="table-wrap"><table class="table"><tr><th>Language</th><th>Next step</th><th>Enables</th><th>Created</th></tr>${v150PlanRows()}</table></div><p class="clean-note"><strong>Major-language scope:</strong> support the major worldwide languages first. Rare, low-confidence, sensitive, or high-stakes requests should route to teacher/staff/professional review instead of pretending every language can be handled perfectly.</p></div></section>`;
  }
